ST.xhtml:p:
IF NOT i_can_evade THEN
  TWA_CalcPriority := 100000.0;
  RETURN;
END_IF;

IF i_phase = 3 THEN
  dist := ABS(i_x_pos - i_x_target);
  IF dist > 99999.0 THEN dist := 99999.0; END_IF;
  TWA_CalcPriority := 200000.0 + (99999.0 - dist);
ELSIF i_phase = 1 THEN
  dist := ABS(i_x_pos - i_x_target);
  IF dist > 99999.0 THEN dist := 99999.0; END_IF;
  TWA_CalcPriority := 100000.0 + (99999.0 - dist);
ELSE
  TWA_CalcPriority := 1.0;
END_IF;

(* Guard *)
IF i_trans < 1 OR i_trans > 3 THEN
  RETURN;
END_IF;

(* Reset output *)
g_dep_idle_slots[i_trans].count := 0;
si := 0;
cnt := g_tasks[i_trans].count;

prev_end  := i_time_s;
prev_sink := 0;

FOR qi := 1 TO 10 DO
  IF qi > cnt THEN
    EXIT;
  END_IF;

  gap_start := prev_end;
  gap_end   := g_tasks[i_trans].queue[qi].start_time;

  (* Only create slot if there is a meaningful gap *)
  IF gap_end > gap_start + 0.1 THEN
    si := si + 1;
    IF si <= 20 THEN
      g_dep_idle_slots[i_trans].slots[si].start_time   := gap_start;
      g_dep_idle_slots[i_trans].slots[si].end_time     := gap_end;
      g_dep_idle_slots[i_trans].slots[si].lift_station := prev_sink;
      g_dep_idle_slots[i_trans].slots[si].sink_station := g_tasks[i_trans].queue[qi].lift_station;
    END_IF;
  END_IF;

  prev_end  := g_tasks[i_trans].queue[qi].finish_time;
  prev_sink := g_tasks[i_trans].queue[qi].sink_station;
END_FOR;

(* Final slot: after last task → open-ended *)
si := si + 1;
IF si <= 20 THEN
  g_dep_idle_slots[i_trans].slots[si].start_time   := prev_end;
  g_dep_idle_slots[i_trans].slots[si].end_time     := HORIZON;
  g_dep_idle_slots[i_trans].slots[si].lift_station := prev_sink;
  g_dep_idle_slots[i_trans].slots[si].sink_station := 0;
END_IF;

g_dep_idle_slots[i_trans].count := si;

g_dep_overlap.count := 0;

FOR stn := 101 TO 125 DO
  cover_count := 0;

  FOR ti := 1 TO 3 DO
    covered := FALSE;
    FOR ai := 1 TO 4 DO
      IF NOT covered THEN
        area := g_cfg[ti].task_area[ai];
        (* Station is covered if within lift OR sink range *)
        IF (area.min_lift > 0 AND stn >= area.min_lift AND stn <= area.max_lift)
           OR (area.min_sink > 0 AND stn >= area.min_sink AND stn <= area.max_sink) THEN
          covered := TRUE;
        END_IF;
      END_IF;
    END_FOR;
    IF covered THEN
      cover_count := cover_count + 1;
    END_IF;
  END_FOR;

  IF cover_count >= 2 THEN
    g_dep_overlap.flags[stn] := TRUE;
    g_dep_overlap.count := g_dep_overlap.count + 1;
  ELSE
    g_dep_overlap.flags[stn] := FALSE;
  END_IF;
END_FOR;

(* Initialize output *)
o_result.fits         := FALSE;
o_result.delay_s      := 0.0;
o_result.need_extra_s := 0.0;
o_result.task_end_s   := 0.0;
o_result.slot_idx     := 0;
o_result.trans_id     := i_trans_id;

IF i_trans_id < 1 OR i_trans_id > 3 THEN
  RETURN;
END_IF;

task_dur   := i_task_end - i_task_start;
flex_up    := i_max_time_s - i_calc_time_s;
IF flex_up < 0.0 THEN flex_up := 0.0; END_IF;
capped_flex := flex_up * i_flex_factor;

slot_cnt   := g_dep_idle_slots[i_trans_id].count;
best_delay := 1.0E9;
best_slot  := 0;
found      := FALSE;

FOR si := 1 TO 20 DO
  IF si > slot_cnt THEN
    EXIT;
  END_IF;

  slot_start := g_dep_idle_slots[i_trans_id].slots[si].start_time;
  slot_end   := g_dep_idle_slots[i_trans_id].slots[si].end_time;

  (* ── Travel time: prev task sink → this lift ── *)
  from_stn := g_dep_idle_slots[i_trans_id].slots[si].lift_station;
  travel_to := 0.0;
  IF from_stn > 0 AND from_stn <> i_lift_stn THEN
    fb_travel_to(i_from_stn := from_stn, i_to_stn := i_lift_stn, i_trans := i_trans_id);
    travel_to := fb_travel_to.o_travel_s;
  END_IF;

  (* ── Travel time: this sink → next task lift ── *)
  to_stn := g_dep_idle_slots[i_trans_id].slots[si].sink_station;
  travel_from := 0.0;
  IF to_stn > 0 AND to_stn <> i_sink_stn THEN
    fb_travel_from(i_from_stn := i_sink_stn, i_to_stn := to_stn, i_trans := i_trans_id);
    travel_from := fb_travel_from.o_travel_s;
  END_IF;

  (* Earliest start = max(slot_start, task_start + shift) + travel_to + margin *)
  IF slot_start > (i_task_start + i_shift_s) THEN
    earliest := slot_start + travel_to + i_margin_s;
  ELSE
    earliest := i_task_start + i_shift_s + travel_to + i_margin_s;
  END_IF;

  (* Latest end = slot_end - travel_from - margin *)
  IF slot_end > 1.0E8 THEN
    (* Open-ended slot *)
    latest := 1.0E8;
  ELSE
    latest := slot_end - travel_from - i_margin_s;
  END_IF;

  (* Check if task fits *)
  IF earliest + task_dur <= latest THEN
    delay := earliest - i_task_start - i_shift_s;
    IF delay < 0.0 THEN delay := 0.0; END_IF;

    (* Flex constraint: delay must not exceed capped flex *)
    IF delay <= capped_flex + i_margin_s THEN
      IF delay < best_delay THEN
        best_delay := delay;
        best_slot  := si;
        found      := TRUE;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

IF found THEN
  o_result.fits      := TRUE;
  o_result.delay_s   := best_delay;
  o_result.slot_idx  := best_slot;
  o_result.task_end_s := i_task_start + i_shift_s + best_delay + task_dur;
  o_result.need_extra_s := 0.0;
ELSE
  (* Report how much extra is needed for backward chaining *)
  (* Use the best near-miss: smallest overshoot beyond capped_flex *)
  o_result.fits := FALSE;
  IF best_delay < 1.0E8 THEN
    o_result.need_extra_s := best_delay - capped_flex;
    IF o_result.need_extra_s < 0.0 THEN
      o_result.need_extra_s := 0.0;
    END_IF;
  ELSE
    o_result.need_extra_s := 0.0;  (* no slot at all *)
  END_IF;
END_IF;

o_delay_s := 0.0;

(* Check if lift/sink are in overlap zone *)
IF i_lift_stn >= 101 AND i_lift_stn <= 125 THEN
  lift_is_overlap := g_dep_overlap.flags[i_lift_stn];
ELSE
  lift_is_overlap := FALSE;
END_IF;
IF i_sink_stn >= 101 AND i_sink_stn <= 125 THEN
  sink_is_overlap := g_dep_overlap.flags[i_sink_stn];
ELSE
  sink_is_overlap := FALSE;
END_IF;

(* No overlap stations involved → no delay *)
IF NOT lift_is_overlap AND NOT sink_is_overlap THEN
  RETURN;
END_IF;

(* Iterative conflict resolution — max 20 rounds *)
FOR round := 1 TO 20 DO
  max_conf := 0.0;
  t_start  := i_task_start + o_delay_s;
  t_end    := i_task_end + o_delay_s;

  (* Check all tasks on OTHER transporters *)
  FOR ti := 1 TO 3 DO
    IF ti <> i_trans_id THEN
      FOR qi := 1 TO 10 DO
        IF qi > g_tasks[ti].count THEN
          EXIT;
        END_IF;

        e_lift  := g_tasks[ti].queue[qi].lift_station;
        e_sink  := g_tasks[ti].queue[qi].sink_station;
        e_start := g_tasks[ti].queue[qi].start_time;
        e_end   := g_tasks[ti].queue[qi].finish_time;

        (* Does existing task share an overlap station? *)
        has_ovlp := FALSE;
        IF lift_is_overlap AND (e_lift = i_lift_stn OR e_sink = i_lift_stn) THEN
          has_ovlp := TRUE;
        END_IF;
        IF sink_is_overlap AND (e_lift = i_sink_stn OR e_sink = i_sink_stn) THEN
          has_ovlp := TRUE;
        END_IF;

        IF has_ovlp THEN
          (* Time overlap check: task overlaps with existing? *)
          IF t_start < (e_end + i_margin_s) AND t_end > (e_start - i_margin_s) THEN
            needed := (e_end + i_margin_s) - t_start;
            IF needed > max_conf THEN
              max_conf := needed;
            END_IF;
          END_IF;
        END_IF;

      END_FOR;  (* qi *)
    END_IF;
  END_FOR;  (* ti *)

  (* No conflict found → done *)
  IF max_conf <= 0.0 THEN
    EXIT;
  END_IF;
  o_delay_s := o_delay_s + max_conf;
END_FOR;  (* round *)

IF i_cmd = 1 THEN
  (* ── SNAPSHOT: globals → sandbox ── *)
  FOR ui := 1 TO 10 DO
    g_dep_sandbox.schedule[ui] := g_schedule[ui];
    g_dep_sandbox.batches[ui]  := g_batches[ui];
    g_dep_sandbox.programs[ui] := g_programs[ui];
  END_FOR;
  FOR ti := 1 TO 3 DO
    g_dep_sandbox.tasks[ti] := g_tasks[ti];
  END_FOR;
  g_dep_sandbox.valid := TRUE;

ELSIF i_cmd = 2 THEN
  (* ── RESTORE: sandbox → globals ── *)
  IF g_dep_sandbox.valid THEN
    FOR ui := 1 TO 10 DO
      g_schedule[ui] := g_dep_sandbox.schedule[ui];
      g_batches[ui]  := g_dep_sandbox.batches[ui];
      g_programs[ui] := g_dep_sandbox.programs[ui];
    END_FOR;
    FOR ti := 1 TO 3 DO
      g_tasks[ti] := g_dep_sandbox.tasks[ti];
    END_FOR;
  END_IF;

ELSIF i_cmd = 3 THEN
  (* ── CLEAR: invalidate sandbox ── *)
  g_dep_sandbox.valid := FALSE;

END_IF;

IF NOT i_run THEN
  phase := 0;
  o_phase := 0;
  o_activated := FALSE;
  RETURN;
END_IF;

next_phase := phase;
o_activated := FALSE;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 0: STOPPED                                           *)
(* ════════════════════════════════════════════════════════════ *)
IF phase = 0 THEN
  next_phase := 1;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1: WAIT_STABLE                                       *)
(* Wait for TSK to be ready (phase >= 10000)                   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1 THEN
  IF i_tsk_phase >= 10000 AND g_dep_stable THEN
    next_phase := 100;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 100: INIT — snapshot sandbox, find waiting batches    *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 100 THEN
  (* Snapshot globals → sandbox (backup for rollback) *)
  fb_sandbox(i_cmd := 1);

  (* Find waiting batches (cur_stage = 90) *)
  fb_collect_wait(i_mode := 1);
  waiting_cnt := fb_collect_wait.o_count;
  FOR ui := 1 TO waiting_cnt DO
    waiting_list[ui] := fb_collect_wait.o_list[ui];
  END_FOR;

  o_wait_cnt := waiting_cnt;
  g_dep_waiting_count := waiting_cnt;
  FOR ui := 1 TO waiting_cnt DO
    g_dep_waiting[ui] := waiting_list[ui];
  END_FOR;

  (* Build active batch list for rebuild phases *)
  fb_collect_all(i_mode := 0);
  batch_count := fb_collect_all.o_count;
  FOR ui := 1 TO batch_count DO
    batch_list[ui] := fb_collect_all.o_list[ui];
  END_FOR;

  IF waiting_cnt = 0 THEN
    (* No waiting batches → back to waiting *)
    fb_sandbox(i_cmd := 3);   (* clear sandbox *)
    next_phase := 1;
  ELSE
    cur_wait_idx := 1;
    next_phase := 200;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 200: CALC_OVERLAP — compute overlap stations          *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 200 THEN
  fb_overlap();
  next_phase := 1000;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1000: BATCH_START — prepare current waiting batch     *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1000 THEN
  IF cur_wait_idx > waiting_cnt THEN
    (* All batches processed, none activated → back to waiting *)
    fb_sandbox(i_cmd := 2);   (* restore globals from snapshot *)
    fb_sandbox(i_cmd := 3);   (* clear sandbox *)
    next_phase := 1;
  ELSE
    cur_wait_unit := waiting_list[cur_wait_idx];
    fit_round := 0;
    sched_base_time := i_time_s;
    next_phase := 1010;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1010: CALC_SCHED — calculate waiting batch schedule   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1010 THEN
  (* Find transporter for this batch based on its location *)
  fb_find_trans(i_lift_stn := g_units[cur_wait_unit].location, i_sink_stn := 0);
  sched_trans := fb_find_trans.o_trans_id;
  IF sched_trans = 0 THEN sched_trans := 1; END_IF;

  (* Calculate schedule using (possibly shifted) base time *)
  fb_calc_sched(
    i_unit   := cur_wait_unit,
    i_trans  := sched_trans,
    i_time_s := sched_base_time
  );

  next_phase := 1020;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1020: REBUILD_TASKS — rebuild all task queues         *)
(* Clear, create for all active batches, sort, swap — one tick *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1020 THEN
  (* Clear all task queues *)
  fb_clear();

  (* Create tasks for ALL active batches *)
  FOR bi := 1 TO batch_count DO
    fb_create_tasks(i_unit := batch_list[bi]);
  END_FOR;

  (* Sort each queue by start_time *)
  fb_sort(i_trans := 0);

  (* Swap same-station pairs *)
  fb_swap_tasks();

  next_phase := 1030;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1030: EXTRACT_WAIT — extract waiting batch tasks      *)
(* Copy waiting batch's tasks to w_tasks[], remove from queues *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1030 THEN
  w_task_cnt := 0;

  FOR ti := 1 TO 3 DO
    write_idx := 0;
    FOR qi := 1 TO g_tasks[ti].count DO
      IF g_tasks[ti].queue[qi].unit = cur_wait_unit THEN
        (* Copy to waiting task array *)
        w_task_cnt := w_task_cnt + 1;
        IF w_task_cnt <= 30 THEN
          w_tasks[w_task_cnt] := g_tasks[ti].queue[qi];
          w_trans[w_task_cnt] := ti;
        END_IF;
      ELSE
        (* Keep in queue — shift down *)
        write_idx := write_idx + 1;
        IF write_idx <> qi THEN
          g_tasks[ti].queue[write_idx] := g_tasks[ti].queue[qi];
        END_IF;
      END_IF;
    END_FOR;
    (* Clear remaining slots *)
    FOR qi := write_idx + 1 TO g_tasks[ti].count DO
      g_tasks[ti].queue[qi].unit := 0;
    END_FOR;
    g_tasks[ti].count := write_idx;
  END_FOR;

  next_phase := 1040;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 1040: CALC_IDLE — calc idle slots for all transporters*)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 1040 THEN
  FOR ti := 1 TO 3 DO
    fb_idle_slots(i_trans := ti, i_time_s := i_time_s);
  END_FOR;
  cur_task_idx := 1;
  next_phase := 2000;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 2000: FIT_STAGE0 — check pickup from loading station *)
(* Uses DEP_FB_FitTaskToSlot to fit the virtual pickup task    *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 2000 THEN
  loading_stn := g_units[cur_wait_unit].location;

  (* Find first treatment station from schedule *)
  first_stn := 0;
  IF g_schedule[cur_wait_unit].stage_count >= 1 THEN
    first_stn := g_schedule[cur_wait_unit].stages[1].station;
  END_IF;

  IF first_stn = 0 OR loading_stn < 100 THEN
    (* No valid schedule or batch not on station → reject *)
    next_phase := 9000;
  ELSE
    (* Find transporter for pickup *)
    fb_find_trans(i_lift_stn := loading_stn, i_sink_stn := first_stn);
    sched_trans := fb_find_trans.o_trans_id;
    IF sched_trans = 0 THEN sched_trans := 1; END_IF;

    (* Calculate transfer time for pickup *)
    fb_xfer(i_from_stn := loading_stn, i_to_stn := first_stn, i_trans := sched_trans);
    xfer_dur := fb_xfer.o_total_s;
    IF xfer_dur < 1.0 THEN xfer_dur := 1.0; END_IF;

    (* Try fitting pickup into idle slots *)
    fb_fit(
      i_lift_stn     := loading_stn,
      i_sink_stn     := first_stn,
      i_trans_id     := sched_trans,
      i_task_start   := sched_base_time,
      i_task_end     := sched_base_time + xfer_dur,
      i_shift_s      := 0.0,
      i_calc_time_s  := 0.0,
      i_max_time_s   := 2.0 * MAX_INIT_WAIT_S,
      i_flex_factor  := FLEX_FACTOR,
      i_margin_s     := MARGIN_S
    );

    IF fb_fit.o_result.fits THEN
      stage0_delay := fb_fit.o_result.delay_s;

      IF stage0_delay > MARGIN_S THEN
        (* Stage 0 needs delay — shift base time and recalculate *)
        sched_base_time := sched_base_time + stage0_delay;
        fit_round := fit_round + 1;
        IF fit_round > MAX_FIT_ROUNDS THEN
          next_phase := 9000;
        ELSE
          (* Recalculate schedule with shifted base time *)
          next_phase := 1010;
        END_IF;
      ELSE
        (* Stage 0 fits → proceed to stage 1+ tasks *)
        IF w_task_cnt = 0 THEN
          next_phase := 8000;  (* No more tasks → ACTIVATE *)
        ELSE
          cur_task_idx := 1;
          next_phase := 2001;
        END_IF;
      END_IF;
    ELSE
      (* Stage 0 doesn't fit → REJECT this batch *)
      next_phase := 9000;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 2001: FIT_TASK — fit stage 1+ tasks one per tick      *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 2001 THEN
  IF cur_task_idx > w_task_cnt THEN
    (* All tasks fit → ACTIVATE *)
    next_phase := 8000;
  ELSE
    (* Get current task data *)
    si := w_tasks[cur_task_idx].stage;
    ti := w_trans[cur_task_idx];

    (* Overlap delay check *)
    fb_ovlp_delay(
      i_lift_stn   := w_tasks[cur_task_idx].lift_station,
      i_sink_stn   := w_tasks[cur_task_idx].sink_station,
      i_trans_id   := ti,
      i_task_start := w_tasks[cur_task_idx].start_time,
      i_task_end   := w_tasks[cur_task_idx].finish_time,
      i_margin_s   := CONFLICT_MARGIN_S
    );
    ovlp_delay_s := fb_ovlp_delay.o_delay_s;

    (* Idle-slot fit check *)
    fb_fit(
      i_lift_stn     := w_tasks[cur_task_idx].lift_station,
      i_sink_stn     := w_tasks[cur_task_idx].sink_station,
      i_trans_id     := ti,
      i_task_start   := w_tasks[cur_task_idx].start_time,
      i_task_end     := w_tasks[cur_task_idx].finish_time,
      i_shift_s      := ovlp_delay_s,
      i_calc_time_s  := w_tasks[cur_task_idx].calc_time,
      i_max_time_s   := w_tasks[cur_task_idx].max_time,
      i_flex_factor  := FLEX_FACTOR,
      i_margin_s     := MARGIN_S
    );

    total_delay_s := ovlp_delay_s + fb_fit.o_result.delay_s;

    IF fb_fit.o_result.fits THEN
      IF total_delay_s <= MARGIN_S THEN
        (* Fits with negligible delay → next task *)
        cur_task_idx := cur_task_idx + 1;
        next_phase := 2001;
      ELSE
        (* Delay needed → record and recalculate *)
        delay_stage  := si;
        delay_amount := total_delay_s;
        delay_target := 1;   (* program stage *)
        next_phase   := 3000;
      END_IF;
    ELSE
      (* Does not fit → REJECT (simplified: no backward chaining) *)
      next_phase := 9000;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 3000: APPLY_DELAY — write delay to program, recalc   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 3000 THEN
  fit_round := fit_round + 1;
  IF fit_round > MAX_FIT_ROUNDS THEN
    next_phase := 9000;
  ELSE
    IF delay_target = 0 THEN
      (* Stage 0 delay: shift base time (handled in FIT_STAGE0, shouldn't reach here) *)
      sched_base_time := sched_base_time + delay_amount;
    ELSIF delay_target = 1 THEN
      (* Program stage delay: increase cal_time *)
      prog_idx := delay_stage;
      IF prog_idx >= 1 AND prog_idx <= 30 THEN
        old_cal := g_programs[cur_wait_unit].stages[prog_idx].cal_time;
        max_cal := g_programs[cur_wait_unit].stages[prog_idx].max_time;
        new_cal := old_cal + REAL_TO_INT(delay_amount);
        IF new_cal > max_cal AND max_cal > 0 THEN
          new_cal := max_cal;
        END_IF;
        g_programs[cur_wait_unit].stages[prog_idx].cal_time := new_cal;
      END_IF;
    END_IF;
    (* Recalculate: schedule → tasks → idle → fit *)
    next_phase := 1010;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8000: ACTIVATE — commit changes to pending write      *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8000 THEN
  (* Store pending write data *)
  FOR ui := 1 TO 10 DO
    g_dep_pending.programs[ui] := g_programs[ui];
    g_dep_pending.schedule[ui] := g_schedule[ui];
  END_FOR;
  g_dep_pending.batch_unit  := cur_wait_unit;
  g_dep_pending.batch_stage := 0;    (* 90 → 0 *)
  g_dep_pending.time_s      := i_time_s;
  g_dep_pending.valid        := TRUE;

  (* Restore globals from sandbox (undo DEP's temp changes) *)
  fb_sandbox(i_cmd := 2);
  fb_sandbox(i_cmd := 3);   (* clear sandbox *)

  g_dep_activated := TRUE;
  o_activated := TRUE;

  next_phase := 8010;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8010: WAIT_SAVE — wait for TSK to process pending     *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8010 THEN
  IF NOT g_dep_pending.valid THEN
    (* TSK has processed the pending write *)
    next_phase := 8020;
  END_IF;
  (* Otherwise keep waiting *)

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8020: END_DELAY — stabilization ticks                 *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8020 THEN
  end_delay_cnt := 0;
  next_phase := 8021;

ELSIF phase >= 8021 AND phase <= 8120 THEN
  end_delay_cnt := end_delay_cnt + 1;
  IF end_delay_cnt >= END_DELAY_TICKS THEN
    next_phase := 8100;
  ELSE
    next_phase := phase + 1;
    IF next_phase > 8120 THEN
      next_phase := 8100;
    END_IF;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 8100: RESTART — back to WAIT_STABLE                   *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 8100 THEN
  g_dep_activated := FALSE;
  next_phase := 1;

(* ════════════════════════════════════════════════════════════ *)
(* PHASE 9000: REJECT — restore, try next batch                *)
(* ════════════════════════════════════════════════════════════ *)
ELSIF phase = 9000 THEN
  (* Restore globals from sandbox (undo changes for this batch) *)
  fb_sandbox(i_cmd := 2);

  (* Try next waiting batch *)
  cur_wait_idx := cur_wait_idx + 1;
  IF cur_wait_idx > waiting_cnt THEN
    (* No more batches → back to waiting *)
    fb_sandbox(i_cmd := 3);
    next_phase := 1;
  ELSE
    (* Try next batch — re-snapshot is still valid *)
    next_phase := 1000;
  END_IF;

(* ════════════════════════════════════════════════════════════ *)
(* Unknown phase → reset                                       *)
(* ════════════════════════════════════════════════════════════ *)
ELSE
  next_phase := 1;
END_IF;

(* ── Phase assignment ── *)
phase := next_phase;
o_phase := phase;

(* --- Clear all stations --- *)
FOR i := 101 TO 125 DO
  g_stations[i].tank_id       := 0;
  g_stations[i].status        := 0;
  g_stations[i].x_position    := 0.0;
  g_stations[i].y_position    := 0.0;
  g_stations[i].z_position    := 0.0;
  g_stations[i].stn_type      := 0;
  g_stations[i].dropping_time := 0.0;
  g_stations[i].device_delay  := 0.0;
END_FOR;
g_station_count := 0;

(* --- Clear all transporter configs --- *)
FOR i := 1 TO 3 DO
  g_cfg[i].x_min_limit   := 0.0;
  g_cfg[i].x_max_limit   := 0.0;
  g_cfg[i].y_min_limit   := 0.0;
  g_cfg[i].y_max_limit   := 0.0;
  g_cfg[i].x_avoid_mm    := 0.0;
  g_cfg[i].y_avoid_mm    := 0.0;
  g_cfg[i].phys2d.x_accel_s     := 0.0;
  g_cfg[i].phys2d.x_decel_s     := 0.0;
  g_cfg[i].phys2d.x_max_mm_s    := 0.0;
  g_cfg[i].phys2d.z_total_mm    := 0.0;
  g_cfg[i].phys2d.z_slow_dry_mm := 0.0;
  g_cfg[i].phys2d.z_slow_wet_mm := 0.0;
  g_cfg[i].phys2d.z_slow_end_mm := 0.0;
  g_cfg[i].phys2d.z_slow_mm_s   := 0.0;
  g_cfg[i].phys2d.z_fast_mm_s   := 0.0;
  g_cfg[i].phys2d.drip_delay_s  := 0.0;
  g_cfg[i].phys2d.avoid_mm      := 0.0;
  FOR j := 1 TO 4 DO
    g_cfg[i].task_area[j].min_lift := 0;
    g_cfg[i].task_area[j].max_lift := 0;
    g_cfg[i].task_area[j].min_sink := 0;
    g_cfg[i].task_area[j].max_sink := 0;
  END_FOR;
END_FOR;

(* --- Clear avoid status --- *)
FOR i := 101 TO 125 DO
  g_avoid_status[i] := 0;
END_FOR;

(* --- Clear all transporter states --- *)
FOR i := 1 TO 3 DO
  g_transporter[i].active          := FALSE;
  g_transporter[i].status          := 0;
  g_transporter[i].phase           := 0;
  g_transporter[i].task_id         := 0.0;
  g_transporter[i].running_task_id := 0.0;
  g_transporter[i].lift_station    := 0;
  g_transporter[i].sink_station    := 0;
  g_transporter[i].treatment_time  := 0.0;
  g_transporter[i].lift_device_delay := 0.0;
  g_transporter[i].sink_device_delay := 0.0;
  g_transporter[i].dropping_time   := 0.0;
  g_transporter[i].remaining_time  := 0.0;
  g_transporter[i].current_station := 0;
  g_transporter[i].final_target_x  := 0.0;
  g_transporter[i].drive_target_x  := 0.0;
  g_transporter[i].final_target_y  := 0.0;
  g_transporter[i].drive_target_y  := 0.0;
  g_transporter[i].x_mm            := 0.0;
  g_transporter[i].y_mm            := 0.0;
  g_transporter[i].z_mm            := 0.0;
  g_transporter[i].vel_x           := 0.0;
  g_transporter[i].z_stage         := 0;
  g_transporter[i].z_timer_s       := 0.0;
  g_transporter[i].x_min_limit     := 0.0;
  g_transporter[i].x_max_limit     := 0.0;
END_FOR;

(* --- Clear all units --- *)
FOR i := 1 TO 10 DO
  g_units[i].location := 0;
  g_units[i].status   := 0;
  g_units[i].state    := 0;
  g_units[i].target   := 0;
END_FOR;

(* --- Clear all batches --- *)
FOR i := 1 TO 10 DO
  g_batches[i].batch_code := 0;
  g_batches[i].state      := 0;
  g_batches[i].prog_id    := 0;
  g_batches[i].cur_stage      := 0;
END_FOR;

(* --- Clear all treatment programs --- *)
FOR i := 1 TO 10 DO
  g_programs[i].program_id := 0;
  FOR j := 1 TO 30 DO
    FOR k := 1 TO 5 DO
      g_programs[i].stages[j].stations[k] := 0;
    END_FOR;
    g_programs[i].stages[j].min_time := 0;
    g_programs[i].stages[j].max_time := 0;
    g_programs[i].stages[j].cal_time := 0;
  END_FOR;
END_FOR;

IF NOT i_run THEN
  RETURN;
END_IF;

FOR i := 1 TO 3 DO
  IF g_transporter[i].active THEN

  (* ── Phase 0 → 1: Accept new task ───────────────────────── *)
  IF (g_transporter[i].phase = 0)
     AND (g_transporter[i].task_id <> g_transporter[i].running_task_id) THEN
    g_transporter[i].running_task_id := g_transporter[i].task_id;
    lookup(station_number := g_transporter[i].lift_station);
    g_transporter[i].final_target_x := lookup.x_mm;
    g_transporter[i].phase := 1;
    g_transporter[i].z_stage := 0;
    g_transporter[i].z_timer_s := 0.0;
  END_IF;

  (* ── Phase 1: Drive X towards lift station ──────────────── *)
  IF g_transporter[i].phase = 1 THEN
    tmp_x  := g_transporter[i].x_mm;
    tmp_vx := g_transporter[i].vel_x;
    IF i = 1 THEN
      fb_x1(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x1.arrived;
    ELSIF i = 2 THEN
      fb_x2(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x2.arrived;
    ELSIF i = 3 THEN
      fb_x3(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x3.arrived;
    END_IF;
    g_transporter[i].x_mm  := tmp_x;
    g_transporter[i].vel_x := tmp_vx;

    IF arrived_x THEN
      g_transporter[i].current_station := g_transporter[i].lift_station;
      lookup(station_number := g_transporter[i].lift_station);
      device_delay := lookup.device_delay_s;
      drop_time    := lookup.dropping_time_s;
      g_transporter[i].z_timer_s := device_delay + drop_time;
      g_transporter[i].z_stage := 1;
      g_transporter[i].phase := 2;
    END_IF;
  END_IF;

  (* ── Phase 2: Lift Z at lift station ────────────────────── *)
  IF g_transporter[i].phase = 2 THEN
    lookup(station_number := g_transporter[i].lift_station);
    station_type := lookup.stype;
    tmp_z  := g_transporter[i].z_mm;
    tmp_zs := g_transporter[i].z_stage;
    tmp_zt := g_transporter[i].z_timer_s;
    IF i = 1 THEN
      fb_z1(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z1.done;
    ELSIF i = 2 THEN
      fb_z2(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z2.done;
    ELSIF i = 3 THEN
      fb_z3(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z3.done;
    END_IF;
    g_transporter[i].z_mm      := tmp_z;
    g_transporter[i].z_stage   := tmp_zs;
    g_transporter[i].z_timer_s := tmp_zt;
    IF arrived_z THEN
      lookup(station_number := g_transporter[i].sink_station);
      g_transporter[i].final_target_x := lookup.x_mm;
      g_transporter[i].phase := 3;
    END_IF;
  END_IF;

  (* ── Phase 3: Drive X towards sink station ─────────────── *)
  IF g_transporter[i].phase = 3 THEN
    tmp_x  := g_transporter[i].x_mm;
    tmp_vx := g_transporter[i].vel_x;
    IF i = 1 THEN
      fb_x1(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x1.arrived;
    ELSIF i = 2 THEN
      fb_x2(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x2.arrived;
    ELSIF i = 3 THEN
      fb_x3(
        delta_t  := 0.02,
        x_target := g_transporter[i].final_target_x,
        x_min    := g_transporter[i].x_min_limit,
        x_max    := g_transporter[i].x_max_limit,
        v_max    := g_cfg[i].phys2d.x_max_mm_s,
        t_acc    := g_cfg[i].phys2d.x_accel_s,
        t_dec    := g_cfg[i].phys2d.x_decel_s,
        x_pos    := tmp_x,
        v_x      := tmp_vx
      );
      arrived_x := fb_x3.arrived;
    END_IF;
    g_transporter[i].x_mm  := tmp_x;
    g_transporter[i].vel_x := tmp_vx;

    IF arrived_x THEN
      g_transporter[i].current_station := g_transporter[i].sink_station;
      lookup(station_number := g_transporter[i].sink_station);
      device_delay := lookup.device_delay_s;
      g_transporter[i].z_timer_s := device_delay + g_cfg[i].phys2d.drip_delay_s;
      g_transporter[i].z_stage := 6;
      g_transporter[i].phase := 4;
    END_IF;
  END_IF;

  (* ── Phase 4: Sink Z at sink station ───────────────────── *)
  IF g_transporter[i].phase = 4 THEN
    lookup(station_number := g_transporter[i].sink_station);
    station_type := lookup.stype;
    tmp_z  := g_transporter[i].z_mm;
    tmp_zs := g_transporter[i].z_stage;
    tmp_zt := g_transporter[i].z_timer_s;
    IF i = 1 THEN
      fb_z1(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z1.done;
    ELSIF i = 2 THEN
      fb_z2(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z2.done;
    ELSIF i = 3 THEN
      fb_z3(
        delta_t       := 0.02,
        station_type  := station_type,
        z_total_mm    := g_cfg[i].phys2d.z_total_mm,
        z_slow_dry_mm := g_cfg[i].phys2d.z_slow_dry_mm,
        z_slow_wet_mm := g_cfg[i].phys2d.z_slow_wet_mm,
        z_slow_end_mm := g_cfg[i].phys2d.z_slow_end_mm,
        z_slow_mm_s   := g_cfg[i].phys2d.z_slow_mm_s,
        z_fast_mm_s   := g_cfg[i].phys2d.z_fast_mm_s,
        drip_delay_s  := g_cfg[i].phys2d.drip_delay_s,
        z_mm          := tmp_z,
        z_stage       := tmp_zs,
        z_timer_s     := tmp_zt
      );
      arrived_z := fb_z3.done;
    END_IF;
    g_transporter[i].z_mm      := tmp_z;
    g_transporter[i].z_stage   := tmp_zs;
    g_transporter[i].z_timer_s := tmp_zt;
    IF arrived_z THEN
      g_transporter[i].phase := 0;
    END_IF;
  END_IF;

  (* ── Nearest station tracking ──────────────────────────── *)
  min_dist := 1.0e9;
  nearest_num := g_transporter[i].current_station;
  FOR idx := 101 TO 125 DO
    IF g_stations[idx].tank_id <> 0 THEN
      dx := g_stations[idx].x_position - g_transporter[i].x_mm;
      IF ABS(dx) < min_dist THEN
        min_dist := ABS(dx);
        nearest_num := idx;
      END_IF;
    END_IF;
  END_FOR;
  g_transporter[i].current_station := nearest_num;

  END_IF;  (* active *)
END_FOR;

IF (x_max > x_min) THEN
  IF x_pos < x_min THEN
    drive_target := x_min;
  ELSIF x_pos > x_max THEN
    drive_target := x_max;
  ELSE
    IF x_target < x_min THEN
      drive_target := x_min;
    ELSIF x_target > x_max THEN
      drive_target := x_max;
    ELSE
      drive_target := x_target;
    END_IF;
  END_IF;
ELSE
  drive_target := x_target;
END_IF;

arrived := ABS(x_pos - drive_target) <= 3.0;
IF arrived THEN
  x_pos := drive_target;
  v_x := 0.0;
  RETURN;
END_IF;

IF t_acc <= 0.0 THEN t_acc := 0.001; END_IF;
IF t_dec <= 0.0 THEN t_dec := 0.001; END_IF;
IF v_max < 0.0 THEN v_max := 0.0; END_IF;

a_acc := v_max / t_acc;
a_dec := v_max / t_dec;

dir := 1.0;
IF drive_target < x_pos THEN
  dir := -1.0;
END_IF;

distance := ABS(drive_target - x_pos);

IF a_dec > 0.0 THEN
  brake_dist := (v_x * v_x) / (2.0 * a_dec);
ELSE
  brake_dist := 0.0;
END_IF;

IF brake_dist >= distance THEN
  new_vel := v_x - a_dec * delta_t;
  IF new_vel < 0.0 THEN new_vel := 0.0; END_IF;
ELSE
  new_vel := v_x + a_acc * delta_t;
  IF new_vel > v_max THEN new_vel := v_max; END_IF;
END_IF;

travel := new_vel * delta_t;
IF travel >= distance THEN
  x_pos := drive_target;
  v_x := 0.0;
  arrived := TRUE;
ELSE
  x_pos := x_pos + dir * travel;
  v_x := new_vel;
  arrived := FALSE;
END_IF;

done := FALSE;

(* Select slow zone based on station type *)
IF station_type = STN_WET THEN
  slow_zone := z_slow_wet_mm;
ELSE
  slow_zone := z_slow_dry_mm;
END_IF;

CASE z_stage OF

  (* === LIFT: stages 1-5 — nosto altaasta ylös === *)

  1: (* Init delay: device_delay + dropping_time *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 2;
      z_mm := z_total_mm;
    END_IF;

  2: (* Slow lift start — hidas nosto nesteestä *)
    z_mm := z_mm - z_slow_mm_s * delta_t;
    IF z_mm <= (z_total_mm - slow_zone) THEN
      z_stage := 3;
    END_IF;

  3: (* Fast lift — nopea nosto *)
    z_mm := z_mm - z_fast_mm_s * delta_t;
    IF z_mm <= z_slow_end_mm THEN
      z_stage := 4;
    END_IF;

  4: (* Slow lift end — hidas loppunosto *)
    z_mm := z_mm - z_slow_mm_s * delta_t;
    IF z_mm <= 0.0 THEN
      z_mm := 0.0;
      z_timer_s := drip_delay_s;
      z_stage := 5;
    END_IF;

  5: (* Drip delay — tippumisviive yläasemassa *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 0;
      done := TRUE;
    END_IF;

  (* === SINK: stages 6-8 — lasku altaaseen === *)

  6: (* Init delay: device_delay + drip_delay *)
    z_timer_s := z_timer_s - delta_t;
    IF z_timer_s <= 0.0 THEN
      z_stage := 7;
    END_IF;

  7: (* Fast sink — nopea lasku *)
    z_mm := z_mm + z_fast_mm_s * delta_t;
    IF z_mm >= (z_total_mm - slow_zone) THEN
      z_stage := 8;
    END_IF;

  8: (* Slow sink — hidas lasku nesteeseen *)
    z_mm := z_mm + z_slow_mm_s * delta_t;
    IF z_mm >= z_total_mm THEN
      z_mm := z_total_mm;
      z_stage := 0;
      done := TRUE;
    END_IF;

END_CASE;

o_travel_s := 0.0;
IF i_from_stn > 0 AND i_to_stn > 0 AND i_from_stn <> i_to_stn THEN
  from_idx := i_from_stn - 100;
  to_idx   := i_to_stn - 100;
  IF from_idx >= 1 AND from_idx <= 25 AND to_idx >= 1 AND to_idx <= 25
     AND i_trans >= 1 AND i_trans <= 3 THEN
    o_travel_s := g_move[i_trans].travel[from_idx].to_s[to_idx];
  END_IF;
END_IF;

o_total_s  := 0.0;
o_lift_s   := 0.0;
o_travel_s := 0.0;
o_sink_s   := 0.0;

IF i_from_stn > 0 AND i_from_stn <> i_to_stn THEN
  from_idx := i_from_stn - 100;
  to_idx   := i_to_stn - 100;
  IF from_idx >= 1 AND from_idx <= 25 AND to_idx >= 1 AND to_idx <= 25
     AND i_trans >= 1 AND i_trans <= 3 THEN
    o_lift_s   := g_move[i_trans].lift_s[from_idx];
    o_travel_s := g_move[i_trans].travel[from_idx].to_s[to_idx];
    o_sink_s   := g_move[i_trans].sink_s[to_idx];
    o_total_s  := o_lift_s + o_travel_s + o_sink_s;
  END_IF;
END_IF;

FOR ti := 1 TO 3 DO
  g_tasks[ti].count := 0;
  FOR qi := 1 TO 10 DO
    g_tasks[ti].queue[qi].unit         := 0;
    g_tasks[ti].queue[qi].stage        := 0;
    g_tasks[ti].queue[qi].lift_station := 0;
    g_tasks[ti].queue[qi].sink_station := 0;
    g_tasks[ti].queue[qi].start_time   := 0.0;
    g_tasks[ti].queue[qi].finish_time  := 0.0;
    g_tasks[ti].queue[qi].calc_time    := 0.0;
    g_tasks[ti].queue[qi].min_time     := 0.0;
    g_tasks[ti].queue[qi].max_time     := 0.0;
  END_FOR;
END_FOR;

o_count := 0;
FOR ui := 1 TO 10 DO
  o_list[ui] := 0;
END_FOR;

FOR ui := 1 TO 10 DO
  IF g_batches[ui].state = 1 THEN
    IF i_mode = 0 THEN
      (* All active batches *)
      o_count := o_count + 1;
      o_list[o_count] := ui;
    ELSIF i_mode = 1 THEN
      (* Waiting batches: stage=90 AND unit target = TO_NONE (0) *)
      IF g_batches[ui].cur_stage = 90 AND g_units[ui].target = 0 THEN
        o_count := o_count + 1;
        o_list[o_count] := ui;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

(* Direct lookup by station number — no loop needed *)
IF (station_number >= 101) AND (station_number <= 125) THEN
  st := g_stations[station_number];
  IF st.tank_id <> 0 THEN
    found := TRUE;
    idx := station_number;
    x_mm := st.x_position;
    stype := st.stn_type;
    device_delay_s := st.device_delay;
    dropping_time_s := st.dropping_time;
    RETURN;
  END_IF;
END_IF;

found := FALSE;
idx := 0;
x_mm := 0.0;
stype := 0;
device_delay_s := 0.0;
dropping_time_s := 0.0;

o_trans_id := 0;
FOR ti := 1 TO 3 DO
  IF o_trans_id = 0 THEN
    FOR ai := 1 TO 4 DO
      IF o_trans_id = 0 THEN
        area := g_cfg[ti].task_area[ai];
        IF area.min_lift > 0 OR area.max_lift > 0 THEN
          can_lift := (i_lift_stn >= area.min_lift) AND (i_lift_stn <= area.max_lift);
          IF i_sink_stn = 0 THEN
            (* Lift-only coverage search *)
            IF can_lift THEN
              o_trans_id := ti;
            END_IF;
          ELSE
            can_sink := (i_sink_stn >= area.min_sink) AND (i_sink_stn <= area.max_sink);
            IF can_lift AND can_sink THEN
              o_trans_id := ti;
            END_IF;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;
  END_IF;
END_FOR;

IF NOT i_run THEN
  (* Stop both schedulers *)
  tsk_sched(i_run := FALSE, i_time_s := 0.0);
  dep_sched(i_run := FALSE, i_time_s := 0.0, i_tsk_phase := 0);
  turn := 0;
  tsk_phase := 0;
  o_tsk_phase := 0;
  o_dep_phase := 0;
  o_turn := 0;
  RETURN;
END_IF;

(* ── Determine this cycle's turn ── *)
IF turn = 0 THEN
  (* First scan: always start with TSK *)
  turn := 1;

ELSIF turn = 1 THEN
  (* Last cycle was TSK → normally DEP's turn *)
  (* But skip DEP if: *)
  (*   a) TSK has not reached READY yet (phase < 10000) *)
  (*   b) pending data waiting for TSK to process *)
  IF tsk_phase < 10000 THEN
    (* TSK still computing — DEP would be blocked at WAIT_STABLE *)
    turn := 1;
    skip_cnt := skip_cnt + 1;
  ELSIF g_dep_pending.valid THEN
    (* TSK must process pending before DEP continues *)
    turn := 1;
    skip_cnt := skip_cnt + 1;
  ELSE
    turn := 2;
  END_IF;

ELSIF turn = 2 THEN
  (* Last cycle was DEP → TSK's turn *)
  turn := 1;
END_IF;

(* ── Execute the selected scheduler ── *)
IF turn = 1 THEN
  (* TSK turn *)
  tsk_sched(i_run := TRUE, i_time_s := i_time_s);
  tsk_phase := tsk_sched.o_phase;

  (* Compute stability flag after TSK call *)
  g_dep_stable := (tsk_phase >= 10000);

ELSIF turn = 2 THEN
  (* DEP turn *)
  dep_sched(
    i_run       := TRUE,
    i_time_s    := i_time_s,
    i_tsk_phase := tsk_phase
  );
END_IF;

(* ── Update outputs ── *)
o_tsk_phase := tsk_sched.o_phase;
o_dep_phase := dep_sched.o_phase;
o_turn      := turn;
o_skip_cnt  := skip_cnt;

(* ---- Phase transition detection ---- *)
IF phase <> prev_phase THEN

  (* -- Save completed measurement and set up next -- *)

  IF prev_phase = 1 AND phase = 2 THEN
    (* Travel to lift complete → save travel time *)
    IF travel_from >= 1 AND travel_from <= 25
       AND travel_to >= 1 AND travel_to <= 25 THEN
      g_move[t_id].travel[travel_from].to_s[travel_to] := timer;
    END_IF;
    (* Start timing lift — timer starts at 0, accumulates only in z_stage 2-4 *)
    lift_idx := lift_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 2 AND phase = 3 THEN
    (* Lift complete → save lift time (pure mechanical Z-motion only) *)
    IF lift_idx >= 1 AND lift_idx <= 25 THEN
      g_move[t_id].lift_s[lift_idx] := timer;
    END_IF;
    (* Start timing travel to sink *)
    travel_from := lift_stn - 100;
    travel_to := sink_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 3 AND phase = 4 THEN
    (* Travel to sink complete → save travel time *)
    IF travel_from >= 1 AND travel_from <= 25
       AND travel_to >= 1 AND travel_to <= 25 THEN
      g_move[t_id].travel[travel_from].to_s[travel_to] := timer;
    END_IF;
    (* Start timing sink — timer starts at 0, accumulates only in z_stage 7-8 *)
    sink_idx := sink_stn - 100;
    timer := 0.0;

  ELSIF prev_phase = 4 AND phase = 0 THEN
    (* Sink complete → save sink time (pure mechanical Z-motion only) *)
    IF sink_idx >= 1 AND sink_idx <= 25 THEN
      g_move[t_id].sink_s[sink_idx] := timer;
    END_IF;
    timer := 0.0;

  ELSIF prev_phase = 0 AND phase = 1 THEN
    (* New cycle starting → set up travel-to-lift *)
    travel_from := from_stn - 100;
    travel_to := lift_stn - 100;
    timer := 0.0;

  ELSE
    (* Unexpected transition → just reset *)
    timer := 0.0;
  END_IF;

  prev_phase := phase;

ELSE
  (* ---- No transition: accumulate timer ---- *)

  IF phase = 1 OR phase = 3 THEN
    (* Travel: only count time when actually moving *)
    (* Filters out TWA collision avoidance stops    *)
    IF ABS(vel_x) > 0.1 THEN
      timer := timer + delta_t;
    END_IF;

  ELSIF phase = 2 THEN
    (* Lift: only mechanical Z-motion stages 2-4 *)
    (* Excludes: stage 1 (device_delay + dropping_time), stage 5 (drip_delay) *)
    IF z_stage >= 2 AND z_stage <= 4 THEN
      timer := timer + delta_t;
    END_IF;

  ELSIF phase = 4 THEN
    (* Sink: only mechanical Z-motion stages 7-8 *)
    (* Excludes: stage 6 (device_delay + drip_delay) *)
    IF z_stage >= 7 AND z_stage <= 8 THEN
      timer := timer + delta_t;
    END_IF;
  END_IF;

END_IF;

IF i_unit < 1 OR i_unit > 10 THEN RETURN; END_IF;
IF ABS(i_amount) < 0.001 THEN RETURN; END_IF;

(* ── Shift schedule stages entry/exit times ── *)
sc := g_schedule[i_unit].stage_count;
FOR si := i_from_stage TO sc DO
  IF si >= 1 AND si <= 30 THEN
    g_schedule[i_unit].stages[si].entry_time :=
      g_schedule[i_unit].stages[si].entry_time + i_amount;
    g_schedule[i_unit].stages[si].exit_time :=
      g_schedule[i_unit].stages[si].exit_time + i_amount;
  END_IF;
END_FOR;

(* ── Shift matching tasks in all transporter queues ── *)
FOR ti := 1 TO 3 DO
  FOR qi := 1 TO g_tasks[ti].count DO
    IF g_tasks[ti].queue[qi].unit = i_unit
       AND g_tasks[ti].queue[qi].stage >= i_from_stage THEN
      g_tasks[ti].queue[qi].start_time :=
        g_tasks[ti].queue[qi].start_time + i_amount;
      g_tasks[ti].queue[qi].finish_time :=
        g_tasks[ti].queue[qi].finish_time + i_amount;
    END_IF;
  END_FOR;
END_FOR;

IF i_trans >= 1 AND i_trans <= 3 THEN
  t_start := i_trans;
  t_end   := i_trans;
ELSE
  t_start := 1;
  t_end   := 3;
END_IF;

FOR ti := t_start TO t_end DO
  ins_cnt := g_tasks[ti].count;
  IF ins_cnt >= 2 THEN
    FOR ins_i := 2 TO ins_cnt DO
      tmp_task := g_tasks[ti].queue[ins_i];
      ins_j := ins_i - 1;
      WHILE ins_j >= 1 AND g_tasks[ti].queue[ins_j].start_time > tmp_task.start_time DO
        g_tasks[ti].queue[ins_j + 1] := g_tasks[ti].queue[ins_j];
        ins_j := ins_j - 1;
      END_WHILE;
      g_tasks[ti].queue[ins_j + 1] := tmp_task;
    END_FOR;
  END_IF;
END_FOR;

o_has_conflict := FALSE;
o_conf_type    := 0;
o_deficit      := 0.0;
checked_count  := 0;
chk_cnt        := 0;

(* ══════ Step 1: Merge all queues into sorted[] by start_time (insertion sort) ══════ *)
sorted_cnt := 0;
FOR ti := 1 TO 3 DO
  FOR qi := 1 TO g_tasks[ti].count DO
    IF g_tasks[ti].queue[qi].unit > 0 THEN
      (* Insert into sorted position *)
      sorted_cnt := sorted_cnt + 1;
      IF sorted_cnt <= 30 THEN
        sorted[sorted_cnt] := g_tasks[ti].queue[qi];
        sorted_trans[sorted_cnt] := ti;
        (* Insertion sort: bubble up *)
        ins := sorted_cnt;
        WHILE ins > 1 DO
          IF sorted[ins].start_time < sorted[ins - 1].start_time THEN
            tmp_task := sorted[ins];
            tmp_tid  := sorted_trans[ins];
            sorted[ins] := sorted[ins - 1];
            sorted_trans[ins] := sorted_trans[ins - 1];
            sorted[ins - 1] := tmp_task;
            sorted_trans[ins - 1] := tmp_tid;
            ins := ins - 1;
          ELSE
            ins := 0; (* break *)
          END_IF;
        END_WHILE;
      END_IF;
    END_IF;
  END_FOR;
END_FOR;

IF sorted_cnt = 0 THEN RETURN; END_IF;

(* ══════ Step 2: Walk sorted list, build checked[], detect conflicts ══════ *)
FOR si := 1 TO sorted_cnt DO

  (* Calculate flex for this task *)
  calc_t := sorted[si].calc_time;
  min_t  := sorted[si].min_time;
  max_t  := sorted[si].max_time;
  f_down := calc_t - min_t;
  IF f_down < 0.0 THEN f_down := 0.0; END_IF;
  f_up := max_t - calc_t;
  IF f_up < 0.0 THEN f_up := 0.0; END_IF;

  (* Get X range for this task *)
  l_idx := sorted[si].lift_station - 100;
  s_idx := sorted[si].sink_station - 100;
  IF l_idx >= 1 AND l_idx <= 25 THEN
    lift_x := g_stations[sorted[si].lift_station].x_position;
  ELSE
    lift_x := 0.0;
  END_IF;
  IF s_idx >= 1 AND s_idx <= 25 THEN
    sink_x := g_stations[sorted[si].sink_station].x_position;
  ELSE
    sink_x := 0.0;
  END_IF;
  IF lift_x < sink_x THEN
    x1_min := lift_x;
    x1_max := sink_x;
  ELSE
    x1_min := sink_x;
    x1_max := lift_x;
  END_IF;

  (* Add to checked list *)
  chk_cnt := chk_cnt + 1;
  IF chk_cnt <= 30 THEN
    chk[chk_cnt].unit        := sorted[si].unit;
    chk[chk_cnt].stage       := sorted[si].stage;
    chk[chk_cnt].transporter := sorted_trans[si];
    chk[chk_cnt].start_time  := sorted[si].start_time;
    chk[chk_cnt].end_time    := sorted[si].finish_time;
    chk[chk_cnt].flex_down   := f_down;
    chk[chk_cnt].flex_up     := f_up;
    chk[chk_cnt].x_min       := x1_min;
    chk[chk_cnt].x_max       := x1_max;
    chk[chk_cnt].is_conflict := FALSE;
  END_IF;

  (* ─── Check TASK_SEQUENCE: same transporter, previous task ─── *)
  (* Find the previous task for this transporter in sorted order *)
  FOR ci := si - 1 TO 1 BY -1 DO
    IF sorted_trans[ci] = sorted_trans[si] THEN
      (* Found previous task on same transporter *)
      prev_sink := sorted[ci].sink_station;
      next_lift := sorted[si].lift_station;

      fb_travel(i_from_stn := prev_sink, i_to_stn := next_lift, i_trans := sorted_trans[si]);
      travel_s := fb_travel.o_travel_s;

      gap_s := sorted[si].start_time - sorted[ci].finish_time;
      deficit_s := travel_s - gap_s;

      IF deficit_s > DEFICIT_TOL THEN
        (* TASK_SEQUENCE conflict! *)
        o_has_conflict  := TRUE;
        o_conf_type     := 1;
        o_conf_unit     := sorted[si].unit;
        o_conf_stage    := sorted[si].stage;
        o_conf_trans    := sorted_trans[si];
        o_blocked_unit  := sorted[ci].unit;
        o_blocked_stage := sorted[ci].stage;
        o_deficit       := deficit_s;
        IF chk_cnt <= 30 THEN
          chk[chk_cnt].is_conflict := TRUE;
        END_IF;
        checked_count := chk_cnt;
        RETURN;
      END_IF;

      EXIT; (* only check immediate predecessor *)
    END_IF;
  END_FOR;

  (* ─── Check TRANSPORTER_COLLISION: different transporter, X+time overlap ─── *)
  FOR ci := 1 TO chk_cnt - 1 DO
    IF chk[ci].transporter <> sorted_trans[si] THEN
      (* X overlap *)
      x2_min := chk[ci].x_min;
      x2_max := chk[ci].x_max;
      xo_start := x1_min;
      IF x2_min > xo_start THEN xo_start := x2_min; END_IF;
      xo_end := x1_max;
      IF x2_max < xo_end THEN xo_end := x2_max; END_IF;

      IF xo_start < xo_end THEN
        (* Time overlap *)
        to_start := sorted[si].start_time;
        IF chk[ci].start_time > to_start THEN to_start := chk[ci].start_time; END_IF;
        to_end := sorted[si].finish_time;
        IF chk[ci].end_time < to_end THEN to_end := chk[ci].end_time; END_IF;

        IF to_start < to_end THEN
          (* TRANSPORTER_COLLISION conflict! *)
          deficit_s := (to_end - to_start) + 2.0; (* +2s margin *)
          o_has_conflict  := TRUE;
          o_conf_type     := 2;
          o_conf_unit     := sorted[si].unit;
          o_conf_stage    := sorted[si].stage;
          o_conf_trans    := sorted_trans[si];
          o_blocked_unit  := chk[ci].unit;
          o_blocked_stage := chk[ci].stage;
          o_deficit       := deficit_s;
          IF chk_cnt <= 30 THEN
            chk[chk_cnt].is_conflict := TRUE;
          END_IF;
          checked_count := chk_cnt;
          RETURN;
        END_IF;
      END_IF;
    END_IF;
  END_FOR;

END_FOR;

(* No conflict found *)
checked_count := chk_cnt;

(* -- Validate inputs -- *)
IF i_unit < 1 OR i_unit > 10 THEN RETURN; END_IF;
IF i_trans < 1 OR i_trans > 3 THEN RETURN; END_IF;

(* -- Read batch and unit data -- *)
cur_stage := g_batches[i_unit].cur_stage;
location  := g_units[i_unit].location;
is_on_stn := location >= 100;
out_count := 0;

(* -- Clear old schedule -- *)
FOR st := 1 TO 30 DO
  g_schedule[i_unit].stages[st].station := 0;
  g_schedule[i_unit].stages[st].entry_time := 0.0;
  g_schedule[i_unit].stages[st].exit_time := 0.0;
  g_schedule[i_unit].stages[st].min_time := 0.0;
  g_schedule[i_unit].stages[st].calc_time := 0.0;
  g_schedule[i_unit].stages[st].max_time := 0.0;
  g_schedule[i_unit].stages[st].transfer_time := 0.0;
END_FOR;

(* -- Determine start stage -- *)
(* Stage 90 = waiting batch, treat as stage 0 *)
IF cur_stage = 90 THEN
  cur_stage := 0;
END_IF;

(* If on transporter, start from next stage; if on station, from current *)
IF is_on_stn THEN
  start_st := cur_stage;
ELSE
  start_st := cur_stage + 1;
END_IF;

(* Force minimum stage 1 *)
IF start_st < 1 THEN
  start_st := 1;
END_IF;

(* -- Previous station (where transfer starts from) -- *)
IF is_on_stn THEN
  prev_stn := location;
ELSIF cur_stage >= 1 AND cur_stage <= 30 THEN
  (* On transporter: use previous stage station *)
  prev_stn := g_programs[i_unit].stages[cur_stage].stations[1];
ELSE
  prev_stn := 0;
END_IF;

(* -- prevExitTime: when next stage can begin -- *)
IF is_on_stn THEN
  (* Unit is on station: calculate remaining time *)
  calc_s := INT_TO_REAL(g_batches[i_unit].cur_stage);
  (* For first stage, remaining time based on calc_time *)
  exit_t := i_time_s;
ELSE
  exit_t := i_time_s;
END_IF;

is_first := TRUE;

(* ============================================================
   MAIN LOOP: Calculate schedule for each program stage
   ============================================================ *)
FOR st := start_st TO 30 DO

  (* Check if stage has a valid station *)
  chosen_stn := 0;
  FOR p := 1 TO 5 DO
    IF g_programs[i_unit].stages[st].stations[p] > 0 AND chosen_stn = 0 THEN
      chosen_stn := g_programs[i_unit].stages[st].stations[p];
    END_IF;
  END_FOR;

  (* No station means end of program *)
  IF chosen_stn = 0 THEN
    EXIT;
  END_IF;

  stn_num := chosen_stn;

  (* Read treatment times from program *)
  calc_s := INT_TO_REAL(g_programs[i_unit].stages[st].cal_time);
  min_s  := INT_TO_REAL(g_programs[i_unit].stages[st].min_time);
  max_s  := INT_TO_REAL(g_programs[i_unit].stages[st].max_time);

  (* -- Calculate transfer time from prev_stn to stn_num -- *)
  fb_xfer(i_from_stn := prev_stn, i_to_stn := stn_num, i_trans := i_trans);
  xfer_t := fb_xfer.o_total_s;

  (* -- Calculate entry and exit times -- *)
  IF is_first AND is_on_stn AND st = cur_stage THEN
    (* Batch is currently at this station *)
    entry_t := i_time_s;
    (* Remaining time: calc_time - elapsed *)
    remain_s := calc_s;
    IF remain_s < 1.0 THEN remain_s := 1.0; END_IF;
    exit_t := i_time_s + remain_s;
  ELSIF is_first AND NOT is_on_stn THEN
    (* Batch is on transporter: entry = now (transfer in progress) *)
    entry_t := exit_t;
    exit_t  := entry_t + calc_s;
  ELSE
    (* Normal stage: entry = prev exit + transfer *)
    entry_t := exit_t + xfer_t;
    exit_t  := entry_t + calc_s;
  END_IF;

  (* -- Write to schedule -- *)
  out_count := out_count + 1;
  IF out_count <= 30 THEN
    g_schedule[i_unit].stages[out_count].station       := stn_num;
    g_schedule[i_unit].stages[out_count].entry_time    := entry_t;
    g_schedule[i_unit].stages[out_count].exit_time     := exit_t;
    g_schedule[i_unit].stages[out_count].min_time      := min_s;
    g_schedule[i_unit].stages[out_count].calc_time     := calc_s;
    g_schedule[i_unit].stages[out_count].max_time      := max_s;
    g_schedule[i_unit].stages[out_count].transfer_time := xfer_t;
  END_IF;

  (* -- Update for next iteration -- *)
  prev_stn := stn_num;
  is_first := FALSE;

END_FOR;

g_schedule[i_unit].stage_count := out_count;

IF i_unit < 1 OR i_unit > 10 THEN RETURN; END_IF;

sc := g_schedule[i_unit].stage_count;
IF sc < 2 THEN RETURN; END_IF;

cur_stage := g_batches[i_unit].cur_stage;
IF cur_stage = 90 THEN
  skip_before := 0;
ELSE
  skip_before := cur_stage;
END_IF;

(* Loop through consecutive stage pairs *)
FOR si := 1 TO sc - 1 DO
  (* schedule index si = current stage, si+1 = next stage *)
  stg_num := si;   (* simplified: schedule stage index = stage number *)

  (* Skip already completed stages *)
  IF stg_num >= skip_before THEN
    lift_stn := g_schedule[i_unit].stages[si].station;
    sink_stn := g_schedule[i_unit].stages[si + 1].station;

    IF lift_stn > 0 AND sink_stn > 0 THEN
      (* -- Find transporter via task_area matching -- *)
      fb_find(i_lift_stn := lift_stn, i_sink_stn := sink_stn);
      tid := fb_find.o_trans_id;

      (* -- Append task to transporter queue -- *)
      IF tid >= 1 AND tid <= 3 THEN
        qi := g_tasks[tid].count + 1;
        IF qi <= 10 THEN
          g_tasks[tid].queue[qi].unit         := i_unit;
          g_tasks[tid].queue[qi].stage        := stg_num;
          g_tasks[tid].queue[qi].lift_station := lift_stn;
          g_tasks[tid].queue[qi].sink_station := sink_stn;
          g_tasks[tid].queue[qi].start_time   := g_schedule[i_unit].stages[si].exit_time;
          g_tasks[tid].queue[qi].finish_time  := g_schedule[i_unit].stages[si + 1].entry_time;
          g_tasks[tid].queue[qi].calc_time    := g_schedule[i_unit].stages[si].calc_time;
          g_tasks[tid].queue[qi].min_time     := g_schedule[i_unit].stages[si].min_time;
          g_tasks[tid].queue[qi].max_time     := g_schedule[i_unit].stages[si].max_time;
          g_tasks[tid].count := qi;
        END_IF;
      END_IF;
    END_IF;
  END_IF;
END_FOR;

FOR ui := 1 TO 10 DO
  tgt := g_units[ui].target;
  loc := g_units[ui].location;

  (* Skip: no target, target is process (handled by schedule), not on station *)
  IF tgt <> 0 AND tgt <> 3 AND loc >= 100 THEN
    (* Find covering transporter *)
    fb_find(i_lift_stn := loc, i_sink_stn := 0);
    cov_t := fb_find.o_trans_id;

    IF cov_t >= 1 AND cov_t <= 3 THEN
      (* Check transporter is idle: phase=0, active *)
      IF g_transporter[cov_t].phase = 0 AND g_transporter[cov_t].active THEN

        (* Find destination station: first available in transporter area *)
        dest_stn := 0;
        FOR ai := 1 TO 4 DO
          IF dest_stn = 0 THEN
            area := g_cfg[cov_t].task_area[ai];
            IF area.min_sink > 0 THEN
              FOR si := area.min_sink TO area.max_sink DO
                IF dest_stn = 0 AND si <> loc AND si >= 101 AND si <= 125 THEN
                  (* Check station is free: no unit there *)
                  stn_free := TRUE;
                  FOR qi := 1 TO 10 DO
                    IF g_units[qi].location = si AND g_units[qi].status = 1 THEN
                      stn_free := FALSE;
                    END_IF;
                  END_FOR;
                  IF stn_free THEN
                    dest_stn := si;
                  END_IF;
                END_IF;
              END_FOR;
            END_IF;
          END_IF;
        END_FOR;

        IF dest_stn > 0 THEN
          (* Calculate timing *)
          fb_xfer(i_from_stn := loc, i_to_stn := dest_stn, i_trans := cov_t);
          xfer_s := fb_xfer.o_total_s;

          task_start := i_time_s;
          task_end   := task_start + xfer_s;

          (* Append to queue *)
          qi := g_tasks[cov_t].count + 1;
          IF qi <= 10 THEN
            g_tasks[cov_t].queue[qi].unit         := ui;
            g_tasks[cov_t].queue[qi].stage        := 0;  (* no program stage *)
            g_tasks[cov_t].queue[qi].lift_station := loc;
            g_tasks[cov_t].queue[qi].sink_station := dest_stn;
            g_tasks[cov_t].queue[qi].start_time   := task_start;
            g_tasks[cov_t].queue[qi].finish_time  := task_end;
            g_tasks[cov_t].queue[qi].calc_time    := 0.0;
            g_tasks[cov_t].queue[qi].min_time     := 0.0;
            g_tasks[cov_t].queue[qi].max_time     := 0.0;
            g_tasks[cov_t].count := qi;
          END_IF;
        END_IF;

      END_IF; (* transporter idle *)
    END_IF; (* covering transporter found *)
  END_IF; (* valid target *)
END_FOR;

o_solved      := FALSE;
o_total_delay := 0.0;
o_total_adv   := 0.0;
remain        := i_deficit;

IF remain <= 0.1 THEN
  o_solved := TRUE;
  RETURN;
END_IF;

(* ══════ Phase 1: ADVANCE prev batch (blocked_unit, blocked_stage) ══════ *)
(* Reduce treatment time toward min_time = flex_down *)

(* Find flex_down for blocked stage in schedule *)
prev_flex := 0.0;
IF i_blocked_unit >= 1 AND i_blocked_unit <= 10 THEN
  sc := g_schedule[i_blocked_unit].stage_count;
  FOR si := 1 TO sc DO
    IF si = i_blocked_stage THEN
      prev_flex := g_schedule[i_blocked_unit].stages[si].calc_time
                 - g_schedule[i_blocked_unit].stages[si].min_time;
      IF prev_flex < 0.0 THEN prev_flex := 0.0; END_IF;
    END_IF;
  END_FOR;
END_IF;

IF prev_flex > 0.1 THEN
  (* Cap: 90% if batch is on this stage, 50% otherwise *)
  IF g_batches[i_blocked_unit].cur_stage = i_blocked_stage THEN
    cap := 0.9;
  ELSE
    cap := 0.5;
  END_IF;
  amount := prev_flex * cap;
  IF amount > remain THEN amount := remain; END_IF;

  (* Apply: shift blocked batch's stage exit earlier + propagate *)
  IF i_blocked_stage >= 1 AND i_blocked_stage <= 30 THEN
    g_schedule[i_blocked_unit].stages[i_blocked_stage].calc_time :=
      g_schedule[i_blocked_unit].stages[i_blocked_stage].calc_time - amount;
    g_schedule[i_blocked_unit].stages[i_blocked_stage].exit_time :=
      g_schedule[i_blocked_unit].stages[i_blocked_stage].exit_time - amount;
    fb_shift(i_unit := i_blocked_unit, i_from_stage := i_blocked_stage + 1, i_amount := -amount);
  END_IF;

  remain := remain - amount;
  o_total_adv := o_total_adv + amount;
END_IF;

IF remain <= 0.1 THEN
  o_solved := TRUE;
  RETURN;
END_IF;

(* ══════ Phase 2: DELAY next batch conflict stage (conf_unit, conf_stage) ══════ *)
(* Increase treatment time toward max_time = flex_up *)
next_flex := 0.0;
IF i_conf_unit >= 1 AND i_conf_unit <= 10 AND i_conf_stage >= 1 AND i_conf_stage <= 30 THEN
  next_flex := g_schedule[i_conf_unit].stages[i_conf_stage].max_time
             - g_schedule[i_conf_unit].stages[i_conf_stage].calc_time;
  IF next_flex < 0.0 THEN next_flex := 0.0; END_IF;
END_IF;

IF next_flex > 0.1 THEN
  IF g_batches[i_conf_unit].cur_stage = i_conf_stage THEN
    cap := 0.9;
  ELSE
    cap := 0.5;
  END_IF;
  amount := next_flex * cap;
  IF amount > remain THEN amount := remain; END_IF;

  (* Apply: extend conflict stage + shift later stages forward *)
  g_schedule[i_conf_unit].stages[i_conf_stage].calc_time :=
    g_schedule[i_conf_unit].stages[i_conf_stage].calc_time + amount;
  g_schedule[i_conf_unit].stages[i_conf_stage].exit_time :=
    g_schedule[i_conf_unit].stages[i_conf_stage].exit_time + amount;
  fb_shift(i_unit := i_conf_unit, i_from_stage := i_conf_stage + 1, i_amount := amount);

  remain := remain - amount;
  o_total_delay := o_total_delay + amount;
END_IF;

IF remain <= 0.1 THEN
  o_solved := TRUE;
  RETURN;
END_IF;

(* ══════ Phase 3: DELAY next batch previous stage (conf_stage - 1) ══════ *)
IF i_conf_stage > 1 THEN
  prev_stage_flex := 0.0;
  IF i_conf_unit >= 1 AND i_conf_unit <= 10 AND (i_conf_stage - 1) >= 1 THEN
    prev_stage_flex := g_schedule[i_conf_unit].stages[i_conf_stage - 1].max_time
                     - g_schedule[i_conf_unit].stages[i_conf_stage - 1].calc_time;
    IF prev_stage_flex < 0.0 THEN prev_stage_flex := 0.0; END_IF;
  END_IF;

  IF prev_stage_flex > 0.1 THEN
    IF g_batches[i_conf_unit].cur_stage = (i_conf_stage - 1) THEN
      cap := 0.9;
    ELSE
      cap := 0.5;
    END_IF;
    amount := prev_stage_flex * cap;
    IF amount > remain THEN amount := remain; END_IF;

    (* Apply: extend previous stage + propagate from conf_stage onward *)
    g_schedule[i_conf_unit].stages[i_conf_stage - 1].calc_time :=
      g_schedule[i_conf_unit].stages[i_conf_stage - 1].calc_time + amount;
    g_schedule[i_conf_unit].stages[i_conf_stage - 1].exit_time :=
      g_schedule[i_conf_unit].stages[i_conf_stage - 1].exit_time + amount;
    fb_shift(i_unit := i_conf_unit, i_from_stage := i_conf_stage, i_amount := amount);

    remain := remain - amount;
    o_total_delay := o_total_delay + amount;
  END_IF;
END_IF;

IF remain <= 0.1 THEN
  o_solved := TRUE;
  RETURN;
END_IF;

(* ══════ Phase 4: DELAY prev past next (forced reorder) ══════ *)
(* Delay blocked_unit's stage to push it past conflict *)
prev_flex := 0.0;
IF i_blocked_unit >= 1 AND i_blocked_unit <= 10 AND i_blocked_stage >= 1 AND i_blocked_stage <= 30 THEN
  prev_flex := g_schedule[i_blocked_unit].stages[i_blocked_stage].max_time
             - g_schedule[i_blocked_unit].stages[i_blocked_stage].calc_time;
  IF prev_flex < 0.0 THEN prev_flex := 0.0; END_IF;
END_IF;

IF prev_flex > 0.1 THEN
  IF g_batches[i_blocked_unit].cur_stage = i_blocked_stage THEN
    cap := 0.9;
  ELSE
    cap := 0.5;
  END_IF;
  amount := prev_flex * cap;
  IF amount > remain THEN amount := remain; END_IF;

  g_schedule[i_blocked_unit].stages[i_blocked_stage].calc_time :=
    g_schedule[i_blocked_unit].stages[i_blocked_stage].calc_time + amount;
  g_schedule[i_blocked_unit].stages[i_blocked_stage].exit_time :=
    g_schedule[i_blocked_unit].stages[i_blocked_stage].exit_time + amount;
  fb_shift(i_unit := i_blocked_unit, i_from_stage := i_blocked_stage + 1, i_amount := amount);

  remain := remain - amount;
  o_total_delay := o_total_delay + amount;
END_IF;

IF remain <= 0.1 THEN
  o_solved := TRUE;
END_IF;

(* If not solved, partial resolution was still applied *)

IF NOT i_run THEN
  phase := 0;
  o_phase := 0;
  RETURN;
END_IF;

next_phase := phase;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 0: STOPPED — wait for i_run                            *)
(* ══════════════════════════════════════════════════════════════ *)
IF phase = 0 THEN
  next_phase := 1;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1: INIT — collect active batches                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1 THEN
  fb_collect(i_mode := 0);
  batch_count := fb_collect.o_count;
  FOR bi := 1 TO batch_count DO
    batch_list[bi] := fb_collect.o_list[bi];
  END_FOR;
  o_batch_cnt := batch_count;
  conflict_iter := 0;

  IF batch_count = 0 THEN
    (* No active batches — go to READY directly *)
    next_phase := 10000;
  ELSE
    next_phase := 1000;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1000: SCHEDULE_START                                   *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1000 THEN
  batch_idx := 1;
  next_phase := 1001;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1001..1010: SCHEDULE per batch (one per tick)          *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase >= 1001 AND phase <= 1010 THEN
  IF batch_idx <= batch_count THEN
    ui := batch_list[batch_idx];

    (* Find transporter for this unit — first one with matching task_area *)
    fb_find(i_lift_stn := g_units[ui].location, i_sink_stn := 0);
    sched_trans := fb_find.o_trans_id;
    IF sched_trans = 0 THEN sched_trans := 1; END_IF;  (* fallback default *)

    fb_calc(i_unit := ui, i_trans := sched_trans, i_time_s := i_time_s);

    batch_idx := batch_idx + 1;
    IF batch_idx <= batch_count THEN
      next_phase := phase + 1;
    ELSE
      next_phase := 1900;
    END_IF;
  ELSE
    next_phase := 1900;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 1900: SCHEDULE_DONE                                    *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 1900 THEN
  next_phase := 2000;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2000: TASKS_START — clear all task queues              *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2000 THEN
  fb_clear();
  batch_idx := 1;
  next_phase := 2001;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2001..2010: CREATE_TASKS per batch (one per tick)      *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase >= 2001 AND phase <= 2010 THEN
  IF batch_idx <= batch_count THEN
    ui := batch_list[batch_idx];
    fb_create(i_unit := ui);
    batch_idx := batch_idx + 1;
    IF batch_idx <= batch_count THEN
      next_phase := phase + 1;
    ELSE
      next_phase := 2200;
    END_IF;
  ELSE
    next_phase := 2200;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2200: TASKS_SORT — insertion sort each queue by time   *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2200 THEN
  fb_sort(i_trans := 0);
  next_phase := 2201;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2201: TASKS_SWAP                                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2201 THEN
  fb_swap();
  next_phase := 2202;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2202: TASKS_ANALYZE                                    *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2202 THEN
  fb_analyze();
  o_conflict := fb_analyze.o_has_conflict;
  IF fb_analyze.o_has_conflict THEN
    next_phase := 2203;
  ELSE
    next_phase := 2204;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2203: TASKS_RESOLVE                                    *)
(* One conflict per cycle → recalculate                         *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2203 THEN
  fb_resolve(
    i_conf_unit     := fb_analyze.o_conf_unit,
    i_conf_stage    := fb_analyze.o_conf_stage,
    i_conf_trans    := fb_analyze.o_conf_trans,
    i_blocked_unit  := fb_analyze.o_blocked_unit,
    i_blocked_stage := fb_analyze.o_blocked_stage,
    i_deficit       := fb_analyze.o_deficit
  );

  conflict_iter := conflict_iter + 1;

  IF conflict_iter >= MAX_CONFLICT_ITER THEN
    (* Max iterations reached — accept partial solution *)
    next_phase := 2204;
  ELSE
    (* Re-analyze: SORT → SWAP → ANALYZE again *)
    next_phase := 2200;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 2204: TASKS_NO_TREATMENT                               *)
(* Task list is stable (no conflicts). Create unit-target tasks *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 2204 THEN
  fb_notrt(i_time_s := i_time_s);
  o_conflict := FALSE;
  next_phase := 10000;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10000: READY — cycle complete                          *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10000 THEN
  (* Count total tasks *)
  total_tasks := 0;
  FOR ti := 1 TO 3 DO
    total_tasks := total_tasks + g_tasks[ti].count;
  END_FOR;
  o_task_cnt := total_tasks;
  next_phase := 10100;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10100: CHECK_DEP_PENDING — DEP activated a batch       *)
(* Copy pending data to globals and trigger full recalculation  *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10100 THEN
  IF g_dep_pending.valid THEN
    (* Apply DEP’s pending data: programs + stage change *)
    FOR ui := 1 TO 10 DO
      g_programs[ui] := g_dep_pending.programs[ui];
    END_FOR;
    IF g_dep_pending.batch_unit >= 1 AND g_dep_pending.batch_unit <= 10 THEN
      g_batches[g_dep_pending.batch_unit].cur_stage := g_dep_pending.batch_stage;
    END_IF;
    g_dep_pending.valid := FALSE;
    (* Full recalculation with new data *)
    next_phase := 1;
  ELSE
    next_phase := 10110;
  END_IF;

(* ══════════════════════════════════════════════════════════════ *)
(* PHASE 10110: RESTART — begin new cycle                       *)
(* ══════════════════════════════════════════════════════════════ *)
ELSIF phase = 10110 THEN
  cycle_count := cycle_count + 1;
  o_cycle_cnt := cycle_count;
  next_phase := 1;  (* back to INIT *)

(* ══════════════════════════════════════════════════════════════ *)
(* Unknown phase → reset to INIT                                *)
(* ══════════════════════════════════════════════════════════════ *)
ELSE
  next_phase := 1;
END_IF;

(* ── Phase assignment at end of scan ── *)
phase := next_phase;
o_phase := phase;

o_swap_count := 0;

FOR ti := 1 TO 3 DO
  cnt := g_tasks[ti].count;
  IF cnt >= 2 THEN
    FOR qi := 1 TO cnt - 1 DO
      (* Check: different units AND prev.sink == next.lift *)
      IF g_tasks[ti].queue[qi].unit <> g_tasks[ti].queue[qi + 1].unit
         AND g_tasks[ti].queue[qi].sink_station = g_tasks[ti].queue[qi + 1].lift_station THEN
        (* Swap *)
        tmp := g_tasks[ti].queue[qi];
        g_tasks[ti].queue[qi] := g_tasks[ti].queue[qi + 1];
        g_tasks[ti].queue[qi + 1] := tmp;
        o_swap_count := o_swap_count + 1;
      END_IF;
    END_FOR;
  END_IF;
END_FOR;

(* ================================================================
   PHASE 1: Station-based restrictions from g_avoid_status
   For each active transporter, search stations near current_station
   and restrict x_min/x_max based on avoid_status 1 (pass) and 2 (block).
   ================================================================ *)
FOR i := 1 TO MAX_TRANSPORTERS DO
  IF NOT g_transporter[i].active THEN
    CONTINUE;
  END_IF;

  min_x := g_cfg[i].x_min_limit;
  max_x := g_cfg[i].x_max_limit;
  current_x := g_transporter[i].x_mm;
  avoid_dist := g_cfg[i].x_avoid_mm;

  (* If no limits configured, lock to current position *)
  IF (min_x < 1.0) OR (max_x < 1.0) THEN
    g_transporter[i].x_min_limit := current_x;
    g_transporter[i].x_max_limit := current_x;
    CONTINUE;
  END_IF;

  has_left_s2 := FALSE;
  has_right_s2 := FALSE;
  left_s2_x := 0.0;
  right_s2_x := 0.0;

  (* --- Search downward (smaller station numbers) from current_station --- *)
  stn_num := g_transporter[i].current_station - 1;
  WHILE stn_num >= 101 DO
    IF g_stations[stn_num].tank_id = 0 THEN
      stn_num := stn_num - 1;
      CONTINUE;
    END_IF;

    stn_x := g_stations[stn_num].x_position;
    IF stn_x < min_x THEN
      EXIT;
    END_IF;

    avoid_st := g_avoid_status[stn_num];

    (* AVOID_PASS: passable unless it is this transporter's target station *)
    IF avoid_st = AVOID_PASS THEN
      is_target := (stn_num = g_transporter[i].lift_station)
               OR  (stn_num = g_transporter[i].sink_station);
      IF is_target THEN
        IF current_x < stn_x THEN
          new_val := stn_x - avoid_dist;
          IF new_val < max_x THEN max_x := new_val; END_IF;
          right_s2_x := stn_x;
          has_right_s2 := TRUE;
        ELSE
          new_val := stn_x + avoid_dist;
          IF new_val > min_x THEN min_x := new_val; END_IF;
          left_s2_x := stn_x;
          has_left_s2 := TRUE;
        END_IF;
        EXIT;
      END_IF;
      (* else: passable, keep searching *)
    END_IF;

    (* AVOID_BLOCK: hard block — transporter cannot cross *)
    IF avoid_st = AVOID_BLOCK THEN
      IF current_x < stn_x THEN
        new_val := stn_x - avoid_dist;
        IF new_val < max_x THEN max_x := new_val; END_IF;
        right_s2_x := stn_x;
        has_right_s2 := TRUE;
      ELSE
        new_val := stn_x + avoid_dist;
        IF new_val > min_x THEN min_x := new_val; END_IF;
        left_s2_x := stn_x;
        has_left_s2 := TRUE;
      END_IF;
      EXIT;
    END_IF;

    stn_num := stn_num - 1;
  END_WHILE;

  (* --- Search upward (larger station numbers) from current_station --- *)
  stn_num := g_transporter[i].current_station + 1;
  WHILE stn_num <= 125 DO
    IF g_stations[stn_num].tank_id = 0 THEN
      stn_num := stn_num + 1;
      CONTINUE;
    END_IF;

    stn_x := g_stations[stn_num].x_position;
    IF stn_x > max_x THEN
      EXIT;
    END_IF;

    avoid_st := g_avoid_status[stn_num];

    IF avoid_st = AVOID_PASS THEN
      is_target := (stn_num = g_transporter[i].lift_station)
               OR  (stn_num = g_transporter[i].sink_station);
      IF is_target THEN
        IF current_x < stn_x THEN
          new_val := stn_x - avoid_dist;
          IF new_val < max_x THEN max_x := new_val; END_IF;
          right_s2_x := stn_x;
          has_right_s2 := TRUE;
        ELSE
          new_val := stn_x + avoid_dist;
          IF new_val > min_x THEN min_x := new_val; END_IF;
          left_s2_x := stn_x;
          has_left_s2 := TRUE;
        END_IF;
        EXIT;
      END_IF;
    END_IF;

    IF avoid_st = AVOID_BLOCK THEN
      IF current_x < stn_x THEN
        new_val := stn_x - avoid_dist;
        IF new_val < max_x THEN max_x := new_val; END_IF;
        right_s2_x := stn_x;
        has_right_s2 := TRUE;
      ELSE
        new_val := stn_x + avoid_dist;
        IF new_val > min_x THEN min_x := new_val; END_IF;
        left_s2_x := stn_x;
        has_left_s2 := TRUE;
      END_IF;
      EXIT;
    END_IF;

    stn_num := stn_num + 1;
  END_WHILE;

  (* Conflict resolution: trapped between two BLOCK stations *)
  IF (min_x >= max_x) AND has_left_s2 AND has_right_s2 THEN
    midpoint := (left_s2_x + right_s2_x) / 2.0;
    min_x := midpoint - 5.0;
    max_x := midpoint + 5.0;
  END_IF;

  g_transporter[i].x_min_limit := min_x;
  g_transporter[i].x_max_limit := max_x;
END_FOR;

(* ================================================================
   STEP 2.0: Basic safety distance — current positions
   Every active transporter pushes neighbors away by x_avoid_mm.
   ================================================================ *)
FOR i := 1 TO MAX_TRANSPORTERS DO
  IF NOT g_transporter[i].active THEN
    CONTINUE;
  END_IF;

  current_x := g_transporter[i].x_mm;
  avoid_dist := g_cfg[i].x_avoid_mm;

  FOR j := 1 TO MAX_TRANSPORTERS DO
    IF j = i THEN CONTINUE; END_IF;
    IF NOT g_transporter[j].active THEN CONTINUE; END_IF;

    other_x := g_transporter[j].x_mm;

    IF other_x > current_x THEN
      (* j is to the RIGHT of i — restrict j's x_min *)
      new_val := current_x + avoid_dist;
      IF new_val > g_transporter[j].x_min_limit THEN
        g_transporter[j].x_min_limit := new_val;
      END_IF;
    ELSIF other_x < current_x THEN
      (* j is to the LEFT of i — restrict j's x_max *)
      new_val := current_x - avoid_dist;
      IF new_val < g_transporter[j].x_max_limit THEN
        g_transporter[j].x_max_limit := new_val;
      END_IF;
    END_IF;
  END_FOR;
END_FOR;

(* ================================================================
   STEP 2.2: Priority-based collision avoidance
   ================================================================ *)

(* --- 2.2.1: Build sorted array of active transporters by x-position --- *)
n_active := 0;
FOR i := 1 TO MAX_TRANSPORTERS DO
  IF g_transporter[i].active THEN
    n_active := n_active + 1;
    w_idx[n_active] := i;
    w_xpos[n_active] := g_transporter[i].x_mm;
    w_phase[n_active] := g_transporter[i].phase;
    w_target[n_active] := g_transporter[i].final_target_x;
    w_avoid[n_active] := g_cfg[i].x_avoid_mm;
  END_IF;
END_FOR;

(* Selection sort by x-position (ascending) *)
FOR i := 1 TO n_active - 1 DO
  min_idx := i;
  FOR j := i + 1 TO n_active DO
    IF w_xpos[j] < w_xpos[min_idx] THEN
      min_idx := j;
    END_IF;
  END_FOR;
  IF min_idx <> i THEN
    tmp_int := w_idx[i];    w_idx[i] := w_idx[min_idx];    w_idx[min_idx] := tmp_int;
    tmp_real := w_xpos[i];  w_xpos[i] := w_xpos[min_idx];  w_xpos[min_idx] := tmp_real;
    tmp_int := w_phase[i];  w_phase[i] := w_phase[min_idx]; w_phase[min_idx] := tmp_int;
    tmp_real := w_target[i]; w_target[i] := w_target[min_idx]; w_target[min_idx] := tmp_real;
    tmp_real := w_avoid[i];  w_avoid[i] := w_avoid[min_idx];  w_avoid[min_idx] := tmp_real;
  END_IF;
END_FOR;

(* --- 2.2.2: Calculate canEvade and priority --- *)
FOR i := 1 TO n_active DO
  k := w_idx[i];

  (* canEvade rules:
     - phase 2 or 4 (Z-movement): cannot evade
     - working area too small: cannot evade *)
  w_can_evade[i] := TRUE;
  IF (w_phase[i] = 2) OR (w_phase[i] = 4) THEN
    w_can_evade[i] := FALSE;
  END_IF;
  work_area := g_transporter[k].x_max_limit - g_transporter[k].x_min_limit;
  IF work_area < MIN_WORK_AREA THEN
    w_can_evade[i] := FALSE;
  END_IF;

  w_priority[i] := TWA_CalcPriority(
    i_phase := w_phase[i],
    i_can_evade := w_can_evade[i],
    i_x_pos := w_xpos[i],
    i_x_target := w_target[i]
  );
END_FOR;

(* Skip Steps 2.2.3-2.2.5 if fewer than 2 active transporters *)
IF n_active >= 2 THEN

  (* --- 2.2.3: Priority restrictions (higher priority → lower priority) --- *)
  FOR i := 1 TO n_active DO
    (* Skip idle transporters — they don't set priority restrictions *)
    IF w_phase[i] = 0 THEN CONTINUE; END_IF;

    FOR j := 1 TO n_active DO
      IF i = j THEN CONTINUE; END_IF;

      (* Determine if i has higher priority than j *)
      a_wins := FALSE;
      IF w_priority[i] > w_priority[j] THEN
        a_wins := TRUE;
      ELSIF (w_priority[i] = w_priority[j]) AND (w_idx[i] < w_idx[j]) THEN
        a_wins := TRUE;
      END_IF;

      IF NOT a_wins THEN CONTINUE; END_IF;

      (* Higher priority transporter uses target for phase 1/3, else current pos *)
      IF (w_phase[i] = 1) OR (w_phase[i] = 3) THEN
        restrict_x := w_target[i];
      ELSE
        restrict_x := w_xpos[i];
      END_IF;

      k := w_idx[j];
      cur_min := g_transporter[k].x_min_limit;
      cur_max := g_transporter[k].x_max_limit;

      IF w_xpos[i] < w_xpos[j] THEN
        (* i is LEFT, j is RIGHT — i sets j's x_min *)
        between := j - i - 1;
        chain_ofs := w_avoid[i] + INT_TO_REAL(between) * (MIN_WORK_AREA + w_avoid[i]);
        new_val := restrict_x + chain_ofs;

        IF new_val > cur_min THEN
          IF new_val <= (cur_max - MIN_WORK_AREA) THEN
            g_transporter[k].x_min_limit := new_val;
          ELSE
            adjusted := cur_max - MIN_WORK_AREA;
            IF adjusted > cur_min THEN
              g_transporter[k].x_min_limit := adjusted;
            END_IF;
          END_IF;
        END_IF;

      ELSIF w_xpos[i] > w_xpos[j] THEN
        (* i is RIGHT, j is LEFT — i sets j's x_max *)
        between := i - j - 1;
        chain_ofs := w_avoid[i] + INT_TO_REAL(between) * (MIN_WORK_AREA + w_avoid[i]);
        new_val := restrict_x - chain_ofs;

        IF new_val < cur_max THEN
          IF new_val >= (cur_min + MIN_WORK_AREA) THEN
            g_transporter[k].x_max_limit := new_val;
          ELSE
            adjusted := cur_min + MIN_WORK_AREA;
            IF adjusted < cur_max THEN
              g_transporter[k].x_max_limit := adjusted;
            END_IF;
          END_IF;
        END_IF;
      END_IF;
    END_FOR;
  END_FOR;

  (* --- 2.2.4: Bidirectional safety (both moving same direction) --- *)
  FOR i := 1 TO n_active - 1 DO
    j := i + 1;
    (* i = left (smaller x), j = right (larger x) — sorted array *)

    left_right := ((w_phase[i] = 1) OR (w_phase[i] = 3)) AND (w_target[i] > w_xpos[i]);
    right_right := ((w_phase[j] = 1) OR (w_phase[j] = 3)) AND (w_target[j] > w_xpos[j]);
    left_left := ((w_phase[i] = 1) OR (w_phase[i] = 3)) AND (w_target[i] < w_xpos[i]);
    right_left := ((w_phase[j] = 1) OR (w_phase[j] = 3)) AND (w_target[j] < w_xpos[j]);

    IF left_right AND right_right THEN
      (* Both moving right — left chasing right *)
      safety_val := w_xpos[i] + w_avoid[i];
      k := w_idx[j];
      IF safety_val > g_transporter[k].x_min_limit THEN
        g_transporter[k].x_min_limit := safety_val;
      END_IF;
    END_IF;

    IF left_left AND right_left THEN
      (* Both moving left — right chasing left *)
      safety_val := w_xpos[j] - w_avoid[j];
      k := w_idx[i];
      IF safety_val < g_transporter[k].x_max_limit THEN
        g_transporter[k].x_max_limit := safety_val;
      END_IF;
    END_IF;
  END_FOR;

  (* --- 2.2.5: Validate limits (trap detection) --- *)
  FOR i := 1 TO n_active DO
    k := w_idx[i];
    IF g_transporter[k].x_min_limit > g_transporter[k].x_max_limit THEN
      (* Trapped — lock in place *)
      g_transporter[k].x_min_limit := g_transporter[k].x_mm;
      g_transporter[k].x_max_limit := g_transporter[k].x_mm;
    END_IF;
  END_FOR;

END_IF;  (* n_active >= 2 *)

(* ============================================================
   CONFIG UPLOAD HANDLER
   Gateway writes station data one at a time via Modbus IW regs.
   Sequence number change triggers processing.
   cmd=1: write_station  cmd=2: init  cmd=3: clear_all
   ============================================================ *)
IF iw_cfg_seq <> last_cfg_seq THEN
  last_cfg_seq := iw_cfg_seq;

  IF iw_cfg_cmd = 3 THEN
    (* --- Clear all config data --- *)
    clear_cfg();
    init_done := FALSE;
    qw_init_done := 0;
    qw_station_cnt := 0;
    qw_cfg_ack := iw_cfg_seq;

  ELSIF iw_cfg_cmd = 1 THEN
    (* --- Write one station to g_stations array --- *)
    IF (iw_cfg_param >= 101) AND (iw_cfg_param <= 125) THEN
      g_stations[iw_cfg_param].tank_id       := iw_cfg_d0;
      g_stations[iw_cfg_param].x_position    := INT_TO_REAL(iw_cfg_d1);
      g_stations[iw_cfg_param].y_position    := INT_TO_REAL(iw_cfg_d2);
      g_stations[iw_cfg_param].z_position    := INT_TO_REAL(iw_cfg_d3);
      g_stations[iw_cfg_param].stn_type      := iw_cfg_d4;
      g_stations[iw_cfg_param].dropping_time := INT_TO_REAL(iw_cfg_d5) / 10.0;
      g_stations[iw_cfg_param].device_delay  := INT_TO_REAL(iw_cfg_d6) / 10.0;
    END_IF;
    qw_cfg_ack := iw_cfg_seq;

  ELSIF iw_cfg_cmd = 4 THEN
    (* --- Write transporter physics page 1 --- *)
    (* param = transporter_id (1..3)
       d0 = x_min_limit mm      d1 = x_max_limit mm
       d2 = x_accel_s × 10      d3 = x_decel_s × 10
       d4 = x_max_mm_s           d5 = z_total_mm
       d6 = avoid_mm *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cfg[j].x_min_limit          := INT_TO_REAL(iw_cfg_d0);
      g_cfg[j].x_max_limit          := INT_TO_REAL(iw_cfg_d1);
      g_cfg[j].phys2d.x_accel_s     := INT_TO_REAL(iw_cfg_d2) / 10.0;
      g_cfg[j].phys2d.x_decel_s     := INT_TO_REAL(iw_cfg_d3) / 10.0;
      g_cfg[j].phys2d.x_max_mm_s    := INT_TO_REAL(iw_cfg_d4);
      g_cfg[j].phys2d.z_total_mm    := INT_TO_REAL(iw_cfg_d5);
      g_cfg[j].phys2d.avoid_mm      := INT_TO_REAL(iw_cfg_d6);
      g_cfg[j].x_avoid_mm           := INT_TO_REAL(iw_cfg_d6);
    END_IF;
    qw_cfg_ack := iw_cfg_seq;

  ELSIF iw_cfg_cmd = 5 THEN
    (* --- Write transporter physics page 2 --- *)
    (* param = transporter_id (1..3)
       d0 = z_slow_dry_mm        d1 = z_slow_wet_mm
       d2 = z_slow_end_mm        d3 = z_slow_mm_s
       d4 = z_fast_mm_s          d5 = drip_delay_s × 10
       d6 = (reserved) *)
    j := iw_cfg_param;
    IF (j >= 1) AND (j <= 3) THEN
      g_cfg[j].phys2d.z_slow_dry_mm := INT_TO_REAL(iw_cfg_d0);
      g_cfg[j].phys2d.z_slow_wet_mm := INT_TO_REAL(iw_cfg_d1);
      g_cfg[j].phys2d.z_slow_end_mm := INT_TO_REAL(iw_cfg_d2);
      g_cfg[j].phys2d.z_slow_mm_s   := INT_TO_REAL(iw_cfg_d3);
      g_cfg[j].phys2d.z_fast_mm_s   := INT_TO_REAL(iw_cfg_d4);
      g_cfg[j].phys2d.drip_delay_s  := INT_TO_REAL(iw_cfg_d5) / 10.0;
    END_IF;
    qw_cfg_ack := iw_cfg_seq;

  ELSIF iw_cfg_cmd = 6 THEN
    (* --- Write transporter task area --- *)
    (* param = transporter_id × 10 + area_index
       e.g. 11 = transporter 1 area 1, 23 = transporter 2 area 3
       d0 = min_lift   d1 = max_lift
       d2 = min_sink   d3 = max_sink *)
    j := iw_cfg_param / 10;
    k := iw_cfg_param MOD 10;
    IF (j >= 1) AND (j <= 3) AND (k >= 1) AND (k <= 4) THEN
      g_cfg[j].task_area[k].min_lift := iw_cfg_d0;
      g_cfg[j].task_area[k].max_lift := iw_cfg_d1;
      g_cfg[j].task_area[k].min_sink := iw_cfg_d2;
      g_cfg[j].task_area[k].max_sink := iw_cfg_d3;
    END_IF;
    qw_cfg_ack := iw_cfg_seq;

  ELSIF iw_cfg_cmd = 2 THEN
    (* --- Finish init: all config uploaded, init transporter states --- *)
    g_station_count := iw_cfg_param;

    FOR i := 1 TO 3 DO
      (* Active if task_area[1] has non-zero stations *)
      IF g_cfg[i].task_area[1].min_lift > 0 THEN
        g_transporter[i].active := TRUE;
      ELSE
        g_transporter[i].active := FALSE;
      END_IF;
      g_transporter[i].phase := 0;
      g_transporter[i].z_stage := 0;
      g_transporter[i].vel_x := 0.0;
      g_transporter[i].z_timer_s := 0.0;
      g_transporter[i].x_min_limit := g_cfg[i].x_min_limit;
      g_transporter[i].x_max_limit := g_cfg[i].x_max_limit;

      (* Start position: use task_area[1].min_lift as start station *)
      IF g_cfg[i].task_area[1].min_lift > 0 THEN
        stn_num := g_cfg[i].task_area[1].min_lift;
      ELSE
        stn_num := 0;
      END_IF;
      lookup(station_number := stn_num);
      IF lookup.found THEN
        g_transporter[i].x_mm := lookup.x_mm;
        g_transporter[i].current_station := stn_num;
      ELSE
        g_transporter[i].x_mm := 0.0;
        g_transporter[i].current_station := 0;
      END_IF;
      g_transporter[i].z_mm := 0.0;
    END_FOR;

    init_done := TRUE;
    qw_cfg_ack := iw_cfg_seq;
  END_IF;
END_IF;

(* ============================================================
   MAIN TRANSPORT CYCLE — only runs when init_done
   ============================================================ *)
IF init_done THEN

(* Calculate transporter working areas (X-limits) every cycle *)
twa_calc();

(* ── Epoch-offset time decode ── *)
(* Server writes iw_epoch_h, iw_time_hi, iw_time_lo via Modbus.
   g_time_s = (iw_time_hi * 65536 + iw_time_lo) / 10.0 *)
g_epoch_h := iw_epoch_h;
g_time_s  := (INT_TO_REAL(iw_time_hi) * 65536.0 + INT_TO_REAL(iw_time_lo)) / 10.0;

(* ── Main Scheduler (TSK + DEP alternating cycles) ── *)
main_sched(i_run := init_done, i_time_s := g_time_s);

(* ── Execute transporter tasks (physics simulation) ── *)
run_tasks(i_run := init_done);

END_IF;  (* init_done *)

(* ============================================================
   UNIT WRITE HANDLER — gateway writes one unit at a time
   ============================================================ *)
IF iw_unit_seq <> last_unit_seq THEN
  last_unit_seq := iw_unit_seq;
  IF (iw_unit_id >= 1) AND (iw_unit_id <= 10) THEN
    g_units[iw_unit_id].location := iw_unit_loc;
    g_units[iw_unit_id].status   := iw_unit_status;
    g_units[iw_unit_id].state    := iw_unit_state;
    g_units[iw_unit_id].target   := iw_unit_target;
  END_IF;
  qw_unit_ack := iw_unit_seq;
END_IF;

(* ============================================================
   BATCH WRITE HANDLER — gateway writes batch data + program_id
   Also clears all stages of the treatment program for this unit.
   ============================================================ *)
IF iw_batch_seq <> last_batch_seq THEN
  last_batch_seq := iw_batch_seq;
  IF (iw_batch_unit >= 1) AND (iw_batch_unit <= 10) THEN
    g_batches[iw_batch_unit].batch_code := iw_batch_code;
    g_batches[iw_batch_unit].state      := iw_batch_state;
    g_batches[iw_batch_unit].prog_id    := iw_batch_prog_id;
    g_batches[iw_batch_unit].cur_stage      := 0;
    g_programs[iw_batch_unit].program_id := iw_batch_prog_id;
    (* Clear all stages *)
    FOR j := 1 TO 30 DO
      FOR k := 1 TO 5 DO
        g_programs[iw_batch_unit].stages[j].stations[k] := 0;
      END_FOR;
      g_programs[iw_batch_unit].stages[j].min_time := 0;
      g_programs[iw_batch_unit].stages[j].max_time := 0;
      g_programs[iw_batch_unit].stages[j].cal_time := 0;
    END_FOR;
  END_IF;
  qw_batch_ack := iw_batch_seq;
END_IF;

(* ============================================================
   PROGRAM STAGE WRITE HANDLER — gateway writes one stage at a time
   ============================================================ *)
IF iw_prog_seq <> last_prog_seq THEN
  last_prog_seq := iw_prog_seq;
  IF (iw_prog_unit >= 1) AND (iw_prog_unit <= 10) AND
     (iw_prog_stage >= 1) AND (iw_prog_stage <= 30) THEN
    g_programs[iw_prog_unit].stages[iw_prog_stage].stations[1] := iw_prog_s1;
    g_programs[iw_prog_unit].stages[iw_prog_stage].stations[2] := iw_prog_s2;
    g_programs[iw_prog_unit].stages[iw_prog_stage].stations[3] := iw_prog_s3;
    g_programs[iw_prog_unit].stages[iw_prog_stage].stations[4] := iw_prog_s4;
    g_programs[iw_prog_unit].stages[iw_prog_stage].stations[5] := iw_prog_s5;
    g_programs[iw_prog_unit].stages[iw_prog_stage].min_time := iw_prog_min_time;
    g_programs[iw_prog_unit].stages[iw_prog_stage].max_time := iw_prog_max_time;
    g_programs[iw_prog_unit].stages[iw_prog_stage].cal_time := iw_prog_cal_time;
  END_IF;
  qw_prog_ack := iw_prog_seq;
END_IF;

(* === MODBUS INPUT: Read commands → g_transporter command fields === *)
(* Note: task_id sync will be handled by SIM_FB_RunTasks later.
   For now, keep the old Modbus command interface working via direct write. *)
IF (iw_cmd_start_1 <> 0) AND (g_transporter[1].phase = 0) THEN
  g_transporter[1].task_id := g_time_s;
  g_transporter[1].lift_station := iw_cmd_lift_1;
  g_transporter[1].sink_station := iw_cmd_sink_1;
END_IF;
IF (iw_cmd_start_2 <> 0) AND (g_transporter[2].phase = 0) THEN
  g_transporter[2].task_id := g_time_s;
  g_transporter[2].lift_station := iw_cmd_lift_2;
  g_transporter[2].sink_station := iw_cmd_sink_2;
END_IF;

(* === MODBUS OUTPUT: Write transporter 1 state === *)
qw_t1_x_mm := REAL_TO_INT(g_transporter[1].x_mm);
qw_t1_z_mm := REAL_TO_INT(g_transporter[1].z_mm);
qw_t1_vel_x10 := REAL_TO_INT(g_transporter[1].vel_x * 10.0);
qw_t1_phase := g_transporter[1].phase;
qw_t1_z_stage := g_transporter[1].z_stage;
qw_t1_cur_st := g_transporter[1].current_station;
qw_t1_lift_tgt := g_transporter[1].lift_station;
qw_t1_sink_tgt := g_transporter[1].sink_station;
IF g_transporter[1].active THEN qw_t1_active := 1; ELSE qw_t1_active := 0; END_IF;

(* === MODBUS OUTPUT: Write transporter 2 state === *)
qw_t2_x_mm := REAL_TO_INT(g_transporter[2].x_mm);
qw_t2_z_mm := REAL_TO_INT(g_transporter[2].z_mm);
qw_t2_vel_x10 := REAL_TO_INT(g_transporter[2].vel_x * 10.0);
qw_t2_phase := g_transporter[2].phase;
qw_t2_z_stage := g_transporter[2].z_stage;
qw_t2_cur_st := g_transporter[2].current_station;
qw_t2_lift_tgt := g_transporter[2].lift_station;
qw_t2_sink_tgt := g_transporter[2].sink_station;
IF g_transporter[2].active THEN qw_t2_active := 1; ELSE qw_t2_active := 0; END_IF;

(* === MODBUS OUTPUT: Status registers === *)
qw_station_cnt := g_station_count;
IF init_done THEN qw_init_done := 1; ELSE qw_init_done := 0; END_IF;
cycle_count := cycle_count + 1;
IF cycle_count > 30000 THEN cycle_count := 0; END_IF;
qw_cycle_cnt := cycle_count;

(* Write unit data to Modbus output QW22..QW61 *)
qw_u1_loc    := g_units[1].location;
qw_u1_status := g_units[1].status;
qw_u1_state  := g_units[1].state;
qw_u1_target := g_units[1].target;
qw_u2_loc    := g_units[2].location;
qw_u2_status := g_units[2].status;
qw_u2_state  := g_units[2].state;
qw_u2_target := g_units[2].target;
qw_u3_loc    := g_units[3].location;
qw_u3_status := g_units[3].status;
qw_u3_state  := g_units[3].state;
qw_u3_target := g_units[3].target;
qw_u4_loc    := g_units[4].location;
qw_u4_status := g_units[4].status;
qw_u4_state  := g_units[4].state;
qw_u4_target := g_units[4].target;
qw_u5_loc    := g_units[5].location;
qw_u5_status := g_units[5].status;
qw_u5_state  := g_units[5].state;
qw_u5_target := g_units[5].target;
qw_u6_loc    := g_units[6].location;
qw_u6_status := g_units[6].status;
qw_u6_state  := g_units[6].state;
qw_u6_target := g_units[6].target;
qw_u7_loc    := g_units[7].location;
qw_u7_status := g_units[7].status;
qw_u7_state  := g_units[7].state;
qw_u7_target := g_units[7].target;
qw_u8_loc    := g_units[8].location;
qw_u8_status := g_units[8].status;
qw_u8_state  := g_units[8].state;
qw_u8_target := g_units[8].target;
qw_u9_loc    := g_units[9].location;
qw_u9_status := g_units[9].status;
qw_u9_state  := g_units[9].state;
qw_u9_target := g_units[9].target;
qw_u10_loc    := g_units[10].location;
qw_u10_status := g_units[10].status;
qw_u10_state  := g_units[10].state;
qw_u10_target := g_units[10].target;

(* Write batch data to Modbus output QW65..QW104 *)
qw_b1_code  := g_batches[1].batch_code;  qw_b1_state  := g_batches[1].state;  qw_b1_prog  := g_batches[1].prog_id;  qw_b1_stage  := g_batches[1].cur_stage;
qw_b2_code  := g_batches[2].batch_code;  qw_b2_state  := g_batches[2].state;  qw_b2_prog  := g_batches[2].prog_id;  qw_b2_stage  := g_batches[2].cur_stage;
qw_b3_code  := g_batches[3].batch_code;  qw_b3_state  := g_batches[3].state;  qw_b3_prog  := g_batches[3].prog_id;  qw_b3_stage  := g_batches[3].cur_stage;
qw_b4_code  := g_batches[4].batch_code;  qw_b4_state  := g_batches[4].state;  qw_b4_prog  := g_batches[4].prog_id;  qw_b4_stage  := g_batches[4].cur_stage;
qw_b5_code  := g_batches[5].batch_code;  qw_b5_state  := g_batches[5].state;  qw_b5_prog  := g_batches[5].prog_id;  qw_b5_stage  := g_batches[5].cur_stage;
qw_b6_code  := g_batches[6].batch_code;  qw_b6_state  := g_batches[6].state;  qw_b6_prog  := g_batches[6].prog_id;  qw_b6_stage  := g_batches[6].cur_stage;
qw_b7_code  := g_batches[7].batch_code;  qw_b7_state  := g_batches[7].state;  qw_b7_prog  := g_batches[7].prog_id;  qw_b7_stage  := g_batches[7].cur_stage;
qw_b8_code  := g_batches[8].batch_code;  qw_b8_state  := g_batches[8].state;  qw_b8_prog  := g_batches[8].prog_id;  qw_b8_stage  := g_batches[8].cur_stage;
qw_b9_code  := g_batches[9].batch_code;  qw_b9_state  := g_batches[9].state;  qw_b9_prog  := g_batches[9].prog_id;  qw_b9_stage  := g_batches[9].cur_stage;
qw_b10_code := g_batches[10].batch_code; qw_b10_state := g_batches[10].state; qw_b10_prog := g_batches[10].prog_id; qw_b10_stage := g_batches[10].cur_stage;
